  function log(message) {
    const entry = document.createElement('div');
    entry.className = 'log-entry';
    entry.textContent = message;
    els.log.prepend(entry);
    while (els.log.children.length > game.logLimit) els.log.removeChild(els.log.lastChild);
  }

  function showBanner(message, duration = 1500) {
    // Disabled per user request (was covering UI)
    return;
}


  function pushDiagnosticEvent(message) {
    const stamp = new Date().toLocaleTimeString();
    game.diagnostics.recentEvents.push(`[${stamp}] ${message}`);
    if (game.diagnostics.recentEvents.length > 30) game.diagnostics.recentEvents.shift();
  }

  function markProgress(reason) {
    game.diagnostics.lastProgressAt = now();
    pushDiagnosticEvent(reason);
  }

  function getPendingSpawnCount() {
    return game.pendingSpawns ? game.pendingSpawns.filter(s => !s.spawned).length : 0;
  }

  function buildProgressHash() {
    const enemySnapshot = game.enemies
      .slice(0, 8)
      .map(e => `${e.id}:${e.x},${e.y}:${Math.round(e.hp)}:${e.attacking ? 1 : 0}`)
      .join('|');
    return [
      game.phase,
      game.runningWave ? 1 : 0,
      game.waveNumber,
      Math.round(game.portalHp),
      game.enemies.length,
      getPendingSpawnCount(),
      enemySnapshot,
    ].join('~');
  }

  function ensureCrashPanel() {
    if (els.crashPanel) return els.crashPanel;
    const panel = document.createElement('div');
    panel.id = 'crashPanel';
    panel.className = 'crash-panel hidden';
    panel.innerHTML = `
      <div class="crash-panel-header">
        <strong>Crash Report</strong>
        <button type="button" id="closeCrashPanelBtn" class="crash-close">×</button>
      </div>
      <div id="crashPanelBody" class="crash-panel-body"></div>
      <div class="crash-panel-actions">
        <button type="button" id="copyCrashReportBtn" class="small-action">Copy Report</button>
      </div>
    `;
    document.body.appendChild(panel);
    panel.querySelector('#closeCrashPanelBtn').addEventListener('click', hideCrashPanel);
    panel.querySelector('#copyCrashReportBtn').addEventListener('click', copyCrashReport);
    els.crashPanel = panel;
    return panel;
  }

  function hideCrashPanel() {
    if (!els.crashPanel) return;
    els.crashPanel.classList.add('hidden');
    game.diagnostics.overlayVisible = false;
  }

  function copyCrashReport() {
    const report = game.diagnostics.lastReport;
    if (!report) return;
    const lines = [
      `${report.title}`,
      `${report.summary}`,
      `State: ${report.stateLine}`,
      'Recent events:',
      ...report.events,
      report.errorLine ? `Error: ${report.errorLine}` : '',
    ].filter(Boolean);
    const payload = lines.join('\n');
    if (navigator.clipboard && navigator.clipboard.writeText) {
      navigator.clipboard.writeText(payload).then(() => showBanner('Crash report copied', 1200)).catch(() => {});
    }
  }

  function inferCrashHint(reportType, errorObj) {
    if (reportType === 'softlock') {
      return 'The game state stopped changing during an active wave. This usually means pathing, aggro, or blocker placement created a deadlock.';
    }
    if (game.portalHp <= 0 && !game.continueOfferUsed) {
      return 'The portal was destroyed. If the screen looked frozen, this was likely a game-over state rather than a true crash.';
    }
    const msg = String(errorObj?.message || errorObj || '');
    if (/undefined|null|Cannot read/i.test(msg)) {
      return 'A unit, tile, or UI element was missing when the game tried to use it.';
    }
    if (/path|move|portal|warrior/i.test(msg)) {
      return 'This likely happened during movement or path validation.';
    }
    return 'An unexpected runtime error occurred.';
  }

  function showCrashReport(reportType, errorObj, extra = {}) {
    if (game.diagnostics.overlayVisible && reportType !== 'softlock') return;
    const panel = ensureCrashPanel();
    const stateLine = `wave=${game.waveNumber} phase=${game.phase} runningWave=${game.runningWave} portalHp=${Math.round(game.portalHp)} enemies=${game.enemies.length} pendingSpawns=${getPendingSpawnCount()} towers=${game.towers.length}`;
    const events = [...game.diagnostics.recentEvents].slice(-10).reverse();
    const errorLine = errorObj ? String(errorObj.stack || errorObj.message || errorObj) : '';
    const title = reportType === 'softlock' ? 'Possible Soft Lock Detected' : 'Runtime Error Detected';
    const summary = extra.summary || inferCrashHint(reportType, errorObj);
    game.diagnostics.lastReport = { title, summary, stateLine, events, errorLine };
    const body = panel.querySelector('#crashPanelBody');
    body.innerHTML = `
      <div class="crash-summary">${summary}</div>
      <div class="crash-state"><strong>State:</strong> ${stateLine}</div>
      ${errorLine ? `<div class="crash-error"><strong>Error:</strong> ${escapeHtml(errorLine)}</div>` : ''}
      <div class="crash-events"><strong>Recent events:</strong><br>${events.map(e => escapeHtml(e)).join('<br>')}</div>
    `;
    panel.classList.remove('hidden');
    game.diagnostics.overlayVisible = true;
    game.runningWave = false;
    game.crashed = true;
    if (game.phase !== SETUP_PHASES.GAME_OVER) {
      setInstruction(reportType === 'softlock' ? 'The game detected a possible soft lock. Review the crash report or start a new run.' : 'The game hit an error. Review the crash report or start a new run.');
    }
    showBanner(reportType === 'softlock' ? 'Possible soft lock detected' : 'Runtime error detected', 2800);
    log(reportType === 'softlock' ? 'Possible soft lock detected. Crash report opened.' : 'Runtime error detected. Crash report opened.');
  }

  function escapeHtml(value) {
    return String(value)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }


  function syncStatusOverlayVisibility(forceHidden = game.introOpen) {
    const overlay = document.getElementById('statusOverlay');
    if (!overlay) return;
    if (forceHidden) {
      overlay.classList.add('hidden');
      overlay.setAttribute('aria-hidden', 'true');
      overlay.style.display = 'none';
      overlay.style.visibility = 'hidden';
      overlay.style.opacity = '0';
      overlay.style.pointerEvents = 'none';
      return;
    }
    overlay.classList.remove('hidden');
    overlay.setAttribute('aria-hidden', 'false');
    overlay.style.display = '';
    overlay.style.visibility = '';
    overlay.style.opacity = '';
    overlay.style.pointerEvents = '';
  }

  function showStatusOverlay(duration = 2500) {
    const overlay = document.getElementById('statusOverlay');
    if (!overlay) return;
    if (game.statusOverlayTimeout) {
      clearTimeout(game.statusOverlayTimeout);
      game.statusOverlayTimeout = null;
    }
    if (game.introOpen || document.body.classList.contains('intro-open')) {
      syncStatusOverlayVisibility(true);
      return;
    }
    overlay.style.left = '';
    overlay.style.right = '';
    overlay.style.top = '';
    overlay.style.bottom = '';
    overlay.style.transform = '';
    syncStatusOverlayVisibility(false);
    game.statusOverlayTimeout = setTimeout(() => {
      syncStatusOverlayVisibility(true);
      game.statusOverlayTimeout = null;
    }, duration);
  }




  const BOUNTY_BOARD_FUNCTION = window.DFK_SUPABASE_BOUNTY_BOARD_FUNCTION || 'bounty-board';
  const CLAIM_BOUNTY_FUNCTION = window.DFK_SUPABASE_CLAIM_BOUNTY_FUNCTION || 'claim-bounty';
  const BOUNTY_RESET_PROGRESS_FUNCTION = window.DFK_SUPABASE_BOUNTY_RESET_PROGRESS_FUNCTION || 'bounty-reset-progress';
  const REQUEST_REWARD_CLAIM_FUNCTION = window.DFK_SUPABASE_REQUEST_REWARD_CLAIM_FUNCTION || 'request-reward-claim';

  function getBountySupabaseConfig() {
    const url = window.DFK_SUPABASE_URL || (window.SUPABASE_CONFIG && window.SUPABASE_CONFIG.url) || '';
    const key = window.DFK_SUPABASE_PUBLISHABLE_KEY || (window.SUPABASE_CONFIG && window.SUPABASE_CONFIG.anonKey) || '';
    return { url, key };
  }

  function getRunTrackerSessionToken() {
    if (!window.DFKRunTracker || typeof window.DFKRunTracker.getState !== 'function') return '';
    const trackerState = window.DFKRunTracker.getState() || {};
    return trackerState.session && trackerState.session.sessionToken ? String(trackerState.session.sessionToken) : '';
  }

  function isSessionAuthFailureMessage(message) {
    return /session not found|session expired|session revoked|wallet mismatch|enable run tracking|missing authorization header|unauthorized|invalid or expired session|session origin mismatch|user agent mismatch/i.test(String(message || ''));
  }

  async function refreshRunTrackerSessionToken(forceRefresh = false) {
    if (!window.DFKRunTracker) return '';
    if (forceRefresh && typeof window.DFKRunTracker.reauthenticate === 'function') {
      const session = await window.DFKRunTracker.reauthenticate();
      return session && session.sessionToken ? String(session.sessionToken) : getRunTrackerSessionToken();
    }
    if (typeof window.DFKRunTracker.authenticate !== 'function') return '';
    const session = await window.DFKRunTracker.authenticate(forceRefresh ? { forceRefresh: true } : undefined);
    return session && session.sessionToken ? String(session.sessionToken) : getRunTrackerSessionToken();
  }

  function buildFunctionAuthHeaders(key, token, includeJson = true) {
    const headers = { apikey: key };
    if (includeJson) headers['Content-Type'] = 'application/json';
    if (token) {
      headers['x-session-token'] = token;
    }
    return headers;
  }

  async function callBountyFunction(functionName, payload = {}, requireAuth = false) {
    const { url, key } = getBountySupabaseConfig();
    if (!url || !key) throw new Error('Supabase bounty board is not configured.');
    let token = getRunTrackerSessionToken();
    if (requireAuth && !token) {
      token = await refreshRunTrackerSessionToken();
      if (!token) throw new Error('Enable run tracking before claiming a bounty.');
    }
    const endpoint = `${url}/functions/v1/${functionName}`;
    const normalizedPayload = payload && typeof payload === 'object' ? { ...payload } : {};
    if (requireAuth && token && !normalizedPayload.sessionToken) {
      normalizedPayload.sessionToken = token;
    }

    const isBoardRead = functionName === BOUNTY_BOARD_FUNCTION && !requireAuth;
    if (isBoardRead) {
      const boardHeaders = buildFunctionAuthHeaders(key, token, false);
      const walletParam = String(normalizedPayload.walletAddress || normalizedPayload.wallet_address || '').trim();
      const cacheBust = encodeURIComponent(String(normalizedPayload._ts || Date.now()));
      const query = walletParam
        ? `?walletAddress=${encodeURIComponent(walletParam)}&wallet_address=${encodeURIComponent(walletParam)}&_ts=${cacheBust}`
        : `?_ts=${cacheBust}`;
      if (walletParam) boardHeaders['x-wallet-address'] = walletParam;
      try {
        const response = await fetch(endpoint + query, { method: 'GET', headers: boardHeaders, cache: 'no-store' });
        const json = await response.json().catch(() => null);
        if (response.ok) return json || {};
      } catch (_error) {}
      try {
        const response = await fetch(endpoint, {
          method: 'POST',
          headers: (() => { const h = buildFunctionAuthHeaders(key, token, true); const w = String(normalizedPayload.walletAddress || normalizedPayload.wallet_address || '').trim(); if (w) h['x-wallet-address'] = w; return h; })(),
          cache: 'no-store',
          body: JSON.stringify(normalizedPayload),
        });
        const json = await response.json().catch(() => null);
        if (response.ok) return json || {};
        throw new Error(json && (json.error || json.message) ? (json.error || json.message) : `Request failed: ${response.status}`);
      } catch (error) {
        const text = String(error && error.message || '');
        throw new Error(text || 'Failed to load bounty board.');
      }
    }

    async function sendRequest(activeToken) {
      const maxAttempts = requireAuth ? 2 : 1;
      let lastError = null;
      for (let attempt = 0; attempt < maxAttempts; attempt += 1) {
        const controller = typeof AbortController !== 'undefined' ? new AbortController() : null;
        const timeoutId = controller ? setTimeout(() => controller.abort(), requireAuth ? 20000 : 12000) : null;
        try {
          const response = await fetch(endpoint, {
            method: 'POST',
            headers: buildFunctionAuthHeaders(key, activeToken, true),
            body: JSON.stringify(normalizedPayload),
            signal: controller ? controller.signal : undefined,
          });
          if (timeoutId) clearTimeout(timeoutId);
          const json = await response.json().catch(() => null);
          if (!response.ok) {
            const primaryMessage = json && (json.error || json.message) ? String(json.error || json.message) : `Request failed: ${response.status}`;
            const details = [];
            if (json && json.code) details.push(`code=${String(json.code)}`);
            if (json && json.dayStartUtc) details.push(`dayStartUtc=${String(json.dayStartUtc)}`);
            if (json && json.latestTrackedRunAt) details.push(`latestTrackedRunAt=${String(json.latestTrackedRunAt)}`);
            if (json && Number.isFinite(Number(json.latestTrackedRunWave))) details.push(`latestTrackedRunWave=${Number(json.latestTrackedRunWave)}`);
            const error = new Error(details.length ? `${primaryMessage} (${details.join(', ')})` : primaryMessage);
            try { error.details = json || null; } catch (_err) {}
            throw error;
          }
          return json || {};
        } catch (error) {
          if (timeoutId) clearTimeout(timeoutId);
          lastError = error;
          const message = String(error && error.message || '');
          const isTransient = /networkerror|failed to fetch|load failed|network request failed|timeout|abort/i.test(message) || (error && error.name === 'AbortError');
          if (!isTransient || attempt >= maxAttempts - 1) throw error;
          await new Promise((resolve) => setTimeout(resolve, 500 * (attempt + 1)));
        }
      }
      throw lastError || new Error('Request failed.');
    }

    try {
      return await sendRequest(token);
    } catch (error) {
      const message = String(error && error.message || '');
      if (!requireAuth || !isSessionAuthFailureMessage(message)) throw error;
      let refreshedToken = '';
      try {
        refreshedToken = await refreshRunTrackerSessionToken(false);
      } catch (_error) {}
      if (!refreshedToken || refreshedToken === token) {
        refreshedToken = await refreshRunTrackerSessionToken(true);
      }
      if (!refreshedToken || refreshedToken === token) throw error;
      return await sendRequest(refreshedToken);
    }
  }

function getRewardClaimPlayerName() {
  const walletState = getWalletStateSnapshot();
  const vanity = String(walletState?.vanityName || '').trim();
  const profile = String(walletState?.profileName || '').trim();
  const wallet = getConnectedWalletAddress();
  return vanity || profile || wallet || 'Unknown player';
}

async function requestRewardClaim(payload = {}) {
  return callBountyFunction(REQUEST_REWARD_CLAIM_FUNCTION, payload, true);
}

function canSubmitRewardClaims() {
  return Boolean(getConnectedWalletAddress() && isRunTrackingEnabled());
}


  function formatBountyCountdown(targetIso, nowIso) {
    const targetMs = new Date(targetIso || 0).getTime();
    const nowMs = new Date(nowIso || Date.now()).getTime();
    const diff = Math.max(0, targetMs - nowMs);
    const totalSeconds = Math.ceil(diff / 1000);
    const hours = Math.floor(totalSeconds / 3600);
    const minutes = Math.floor((totalSeconds % 3600) / 60);
    const seconds = totalSeconds % 60;
    return `${String(hours).padStart(2, '0')}:${String(minutes).padStart(2, '0')}:${String(seconds).padStart(2, '0')}`;
  }

  function getBountyCardClass(status) {
    if (status === 'claimed') return 'is-claimed';
    if (status === 'open') return 'is-open';
    return 'is-locked';
  }

  function getBountyStateLabel(entry, currentTimeIso) {
    if (entry.status === 'claimed') return 'Claimed';
    if (entry.status === 'open') return 'Open Now';
    if (entry.status === 'cooldown' && entry.revealAt) return `Reveals In ${formatBountyCountdown(entry.revealAt, currentTimeIso)}`;
    return 'Locked';
  }

  function escapeHtml(value) {
    return String(value == null ? '' : value)
      .replace(/&/g, '&amp;')
      .replace(/</g, '&lt;')
      .replace(/>/g, '&gt;')
      .replace(/"/g, '&quot;')
      .replace(/'/g, '&#39;');
  }

  function formatTrackedRunTimestamp(value) {
    if (!value) return 'Time unavailable';
    const date = new Date(value);
    if (Number.isNaN(date.getTime())) return 'Time unavailable';
    return date.toLocaleString(undefined, {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
      hour: 'numeric',
      minute: '2-digit',
    });
  }

  function getTrackedRunChainLabel(chainId) {
    const numericChainId = Number(chainId || 0);
    if (numericChainId === 53935) return 'DFK Chain';
    if (numericChainId === Number(window.DFK_AVAX_CHAIN_ID || 43114)) return 'AVAX';
    return numericChainId > 0 ? `Chain ${numericChainId}` : 'Chain unknown';
  }

  function getTrackedRunTimestampValue(run) {
    const raw = run && (run.completedAt || run.createdAt || run.runStartedAt || null);
    const value = raw ? new Date(raw).getTime() : 0;
    return Number.isFinite(value) ? value : 0;
  }

  function getTrackedRunChainSortValue(chainId) {
    const numericChainId = Number(chainId || 0);
    if (numericChainId === 53935) return 0;
    if (numericChainId === Number(window.DFK_AVAX_CHAIN_ID || 43114)) return 1;
    if (numericChainId > 0) return 2;
    return 3;
  }

  function sortTrackedRuns(runs, sortMode) {
    const list = Array.isArray(runs) ? runs.slice() : [];
    const mode = String(sortMode || 'date_desc');
    list.sort((a, b) => {
      const aWave = Number(a && a.bestWave || 0) || 0;
      const bWave = Number(b && b.bestWave || 0) || 0;
      const aRunNumber = Number(a && a.runNumber || 0) || 0;
      const bRunNumber = Number(b && b.runNumber || 0) || 0;
      const aTime = getTrackedRunTimestampValue(a);
      const bTime = getTrackedRunTimestampValue(b);
      const aChain = getTrackedRunChainSortValue(a && a.chainId);
      const bChain = getTrackedRunChainSortValue(b && b.chainId);
      if (mode === 'date_asc') {
        if (aTime !== bTime) return aTime - bTime;
        if (aWave !== bWave) return bWave - aWave;
        return aRunNumber - bRunNumber;
      }
      if (mode === 'wave_desc') {
        if (aWave !== bWave) return bWave - aWave;
        if (aTime !== bTime) return bTime - aTime;
        return aRunNumber - bRunNumber;
      }
      if (mode === 'wave_asc') {
        if (aWave !== bWave) return aWave - bWave;
        if (aTime !== bTime) return bTime - aTime;
        return aRunNumber - bRunNumber;
      }
      if (mode === 'chain_asc') {
        if (aChain !== bChain) return aChain - bChain;
        if (aWave !== bWave) return bWave - aWave;
        if (aTime !== bTime) return bTime - aTime;
        return aRunNumber - bRunNumber;
      }
      if (aTime !== bTime) return bTime - aTime;
      if (aWave !== bWave) return bWave - aWave;
      return aRunNumber - bRunNumber;
    });
    return list;
  }

  function renderTrackedRunsBoard() {
    if (!els.trackedRunsBody) return;
    const state = game.bountyBoard || {};
    if (state.loading && (!state.runs || !state.runs.length)) {
      els.trackedRunsBody.innerHTML = '<div class="bounty-status-banner">Loading tracked runs…</div>';
      return;
    }
    if (state.error && (!state.runs || !state.runs.length)) {
      els.trackedRunsBody.innerHTML = `<div class="bounty-status-banner is-error">${escapeHtml(/failed to fetch|401|400|403|cors/i.test(String(state.error || '')) ? 'Tracked runs are unavailable right now.' : state.error)}</div>`;
      return;
    }
    const allRuns = Array.isArray(state.runs) ? state.runs : [];
    const runs = sortTrackedRuns(
      allRuns.filter((run) => (Number(run.bestWave || 0) || 0) > 0),
      game.trackedRunsSortMode || 'date_desc'
    );
    if (!runs.length) {
      els.trackedRunsBody.innerHTML = '<div class="bounty-status-banner">No tracked runs yet. Runs with 0 waves completed are not shown.</div>';
      return;
    }
    const search = String(game.trackedRunsSearchQuery || '').trim().toLowerCase();
    const filteredRuns = runs.filter((run) => {
      if (!search) return true;
      const id = String(run.id || '').toLowerCase();
      const shortId = id.slice(0, 8);
      const wave = String(Number(run.bestWave || 0) || 0);
      const runNumber = String(Number(run.runNumber || 0) || 0);
      const chainLabel = String(getTrackedRunChainLabel(run.chainId)).toLowerCase();
      const timestamp = String(formatTrackedRunTimestamp(run.completedAt || run.createdAt || run.runStartedAt || null)).toLowerCase();
      return id.includes(search) || shortId.includes(search) || wave.includes(search) || runNumber.includes(search) || chainLabel.includes(search) || timestamp.includes(search);
    });
    const items = filteredRuns.map((run) => {
      const runNumber = Number(run.runNumber || 0) || 0;
      const bestWave = Number(run.bestWave || 0) || 0;
      const shortId = String(run.id || '').slice(0, 8) || 'unknown';
      const used = Boolean(run.used);
      const chainLabel = getTrackedRunChainLabel(run.chainId);
      const timestampLabel = formatTrackedRunTimestamp(run.completedAt || run.createdAt || run.runStartedAt || null);
      const claimedBountyText = escapeHtml(run.claimedBountyTitle || run.claimedBountyName || run.bountyTitle || (run.claimedBountyId ? `Bounty ${run.claimedBountyId}` : 'Bounty claim'));
      const statusText = used ? `Used for ${claimedBountyText}` : 'Available';
      const cachedRunStats = getCachedTrackedRunStats(run.id);
      const enrichedRun = cachedRunStats ? {
        ...run,
        replayShareId: run.replayShareId || run.replay_share_id || cachedRunStats.replayShareId || '',
        heroes: Array.isArray(run.heroes) && run.heroes.length ? run.heroes : (Array.isArray(cachedRunStats.heroesUsed) ? cachedRunStats.heroesUsed.map((name) => ({ className: name })) : []),
        foundRelicIds: Array.isArray(run.foundRelicIds) && run.foundRelicIds.length ? run.foundRelicIds : (Array.isArray(cachedRunStats.relicsFound) ? cachedRunStats.relicsFound : []),
        stats: {
          ...(run.stats && typeof run.stats === 'object' ? run.stats : {}),
          foundRelicIds: Array.isArray(run.foundRelicIds) && run.foundRelicIds.length ? run.foundRelicIds : (Array.isArray(cachedRunStats.relicsFound) ? cachedRunStats.relicsFound : ((run.stats && run.stats.foundRelicIds) || [])),
        },
      } : run;
      const replayShareId = sanitizeReplayText(enrichedRun.replayShareId || enrichedRun.replay_share_id || getCachedTrackedRunReplayShareId(enrichedRun.id));
      const replayUrl = replayShareId ? buildReplayShareUrl(replayShareId) : '';
      const replayBlock = replayUrl
        ? `
          <div class="tracked-run-replay-row">
            <button type="button" class="tracked-run-replay-stats" data-run-stats-id="${escapeHtml(String(run.id || ''))}" data-run-stats="${escapeHtml(encodeRunStatsButtonPayload(enrichedRun))}">Run Stats</button>
            <button type="button" class="tracked-run-replay-copy tracked-run-replay-copy-small" data-copy-replay-url="${escapeHtml(replayUrl)}">Copy URL</button>
          </div>
          <div class="tracked-run-replay-url" title="${escapeHtml(replayUrl)}">${escapeHtml(replayUrl)}</div>
        `
        : `
          <div class="tracked-run-replay-row">
            <button type="button" class="tracked-run-replay-stats" data-run-stats-id="${escapeHtml(String(run.id || ''))}" data-run-stats="${escapeHtml(encodeRunStatsButtonPayload(enrichedRun))}">Run Stats</button>
          </div>
          <div class="tracked-run-replay-url tracked-run-replay-url-missing" title="Replay not available for this run yet.">Replay not available for this run yet.</div>
        `;
      return `
        <article class="tracked-run-card ${used ? 'is-used' : 'is-available'}">
          <div class="tracked-run-card-top">
            <div>
              <div class="tracked-run-label">Run ${runNumber}</div>
              <div class="tracked-run-id">#${escapeHtml(shortId)}</div>
            </div>
            <div class="tracked-run-wave">Wave ${bestWave}</div>
          </div>
          <div class="tracked-run-meta-row">
            <div class="tracked-run-meta-pill">${escapeHtml(chainLabel)}</div>
            <div class="tracked-run-meta-time">${escapeHtml(timestampLabel)}</div>
          </div>
          <div class="tracked-run-status ${used ? 'is-used' : 'is-available'}">${statusText}</div>
          ${replayBlock}
        </article>
      `;
    }).join('');
    const emptyState = filteredRuns.length
      ? `<div class="tracked-runs-grid">${items}</div>`
      : '<div class="bounty-status-banner">No tracked runs match that search.</div>';
    els.trackedRunsBody.innerHTML = `
      <div class="tracked-runs-hero-strip">
        <div>
          <div class="bounty-strip-kicker">Tracked run ledger</div>
          <p class="bounty-strip-copy">Bounty claims always consume the lowest qualifying unused run. Runs highlighted in green have already been spent on a bounty.</p>
          <p class="tracked-runs-note">Runs with 0 waves completed are not shown.</p>
        </div>
        <div class="bounty-strip-badge">${filteredRuns.length}/${runs.length} tracked run${runs.length === 1 ? '' : 's'}</div>
      </div>
      <div class="tracked-runs-controls">
        <label class="tracked-runs-search-wrap">
          <span class="tracked-runs-search-label">Search by run ID or waves completed</span>
          <input id="trackedRunsSearchInput" class="tracked-runs-search-input" type="search" placeholder="Search by ID or wave" value="${escapeHtml(game.trackedRunsSearchQuery || '')}" />
        </label>
        <label class="tracked-runs-sort-wrap">
          <span class="tracked-runs-search-label">Sort tracked runs</span>
          <select id="trackedRunsSortSelect" class="tracked-runs-sort-select">
            <option value="date_desc" ${String(game.trackedRunsSortMode || 'date_desc') === 'date_desc' ? 'selected' : ''}>Date: newest first</option>
            <option value="date_asc" ${String(game.trackedRunsSortMode || '') === 'date_asc' ? 'selected' : ''}>Date: oldest first</option>
            <option value="wave_desc" ${String(game.trackedRunsSortMode || '') === 'wave_desc' ? 'selected' : ''}>Wave: highest first</option>
            <option value="wave_asc" ${String(game.trackedRunsSortMode || '') === 'wave_asc' ? 'selected' : ''}>Wave: lowest first</option>
            <option value="chain_asc" ${String(game.trackedRunsSortMode || '') === 'chain_asc' ? 'selected' : ''}>Chain: DFK → AVAX → other</option>
          </select>
        </label>
      </div>
      ${emptyState}
    `;
  }

  function openTrackedRunsModal() {
    if (game.statusOverlayTimeout) {
      clearTimeout(game.statusOverlayTimeout);
      game.statusOverlayTimeout = null;
    }
    closeIntroModal();
    closeBountyModal();
    closeQuestsModal();
    closeKnownRelicsModal();
    renderTrackedRunsBoard();
    if (window.DFKRunTracker) {
      if (typeof window.DFKRunTracker.authenticate === 'function' && typeof window.DFKRunTracker.isTrackingEnabled === 'function' && window.DFKRunTracker.isTrackingEnabled()) {
        window.DFKRunTracker.authenticate().catch(() => {});
      }
      if (typeof window.DFKRunTracker.flushPendingRuns === 'function') {
        window.DFKRunTracker.flushPendingRuns({ interactive: true, force: true }).catch(() => {});
      }
      if (typeof window.DFKRunTracker.refreshSummary === 'function') {
        window.DFKRunTracker.refreshSummary({ flushPending: true }).catch(() => {});
      }
    }
    refreshBountyBoard().catch(() => {});
    game.introOpen = true;
    syncStatusOverlayVisibility(true);
    document.body.classList.add('intro-open');
    if (els.trackedRunsModal) {
      els.trackedRunsModal.classList.remove('hidden');
      els.trackedRunsModal.setAttribute('aria-hidden', 'false');
    }
  }

  function closeTrackedRunsModal() {
    if (els.questsModal) {
      els.questsModal.classList.add('hidden');
      els.questsModal.setAttribute('aria-hidden', 'true');
    }
    if (els.trackedRunsModal) {
      els.trackedRunsModal.classList.add('hidden');
      els.trackedRunsModal.setAttribute('aria-hidden', 'true');
    }
    if (els.newsModal) {
      els.newsModal.classList.add('hidden');
      els.newsModal.setAttribute('aria-hidden', 'true');
    }
    syncQuestModalInteractivity(false);
    game.introOpen = false;
    document.body.classList.remove('intro-open');
    syncStatusOverlayVisibility(false);
    showStatusOverlay();
  }


  function renderBountyBoard() {
    hydrateBountyClaimLockState(getConnectedWalletAddress());
    const bountyTargetBody = (game.questBoardView === 'bounty' && els.questsBody) ? els.questsBody : els.bountyBody;
    if (!bountyTargetBody) return;
    const state = game.bountyBoard || {};
    ensureWeeklyBountyProgress();
    if (state.loading && !state.entries.length) {
      bountyTargetBody.innerHTML = '<div class="bounty-status-banner">Loading weekly bounties…</div>';
      return;
    }
    if (state.error && !state.entries.length) {
      bountyTargetBody.innerHTML = `<div class="bounty-status-banner is-error">${state.error}</div>`;
      return;
    }
    const activeWeekKey = String(state.weekKey || getWeeklyBountyWeekKey());
    const entries = Array.isArray(state.entries) && state.entries.length
      ? state.entries
      : getClientWeeklyBountyEntries(activeWeekKey, []);
    const pendingTrackedRunCount = getPendingTrackedRunCount(getConnectedWalletAddress());
    const cards = entries.map((entry, index) => {
      const progress = getWeeklyBountyDisplayProgressValue(entry);
      const claimProgress = getWeeklyBountyClaimProgressValue(entry);
      const goal = Math.max(0, Number(entry.goal || 0) || 0);
      const claimLimit = Math.max(1, Number(entry.claimLimit || 3) || 3);
      const claimCount = Math.max(0, Number(entry.claimCount || 0) || 0);
      const claimNames = getWeeklyBountyClaimNames(entry);
      const viewerHasClaimed = !!entry.viewerHasClaimed;
      const full = claimCount >= claimLimit;
      const complete = claimProgress >= goal && goal > 0;
      const hasPendingProgress = progress > claimProgress;
      const hasPendingSubmission = pendingTrackedRunCount > 0;
      const pendingCompletion = !complete && goal > 0 && progress >= goal && hasPendingSubmission;
      const recentTrackedRunSubmitted = hasRecentTrackedRunSubmission(getConnectedWalletAddress());
      const syncDebugState = getBountySyncDebugState(state);
      const debugInfo = (state.debug && state.debug.entriesById && state.debug.entriesById[entry.id]) ? state.debug.entriesById[entry.id] : null;
      if (!hasPendingSubmission && recentTrackedRunSubmitted && syncDebugState.latestPlaceholder) {
        clearRecentTrackedRunSubmission(getConnectedWalletAddress());
        const weeklyState = ensureWeeklyBountyProgress();
        if (weeklyState) weeklyState.dirtySessionMetrics = false;
      }
      const awaitingServerSync = !complete && goal > 0 && progress >= goal && !hasPendingSubmission && recentTrackedRunSubmitted && !syncDebugState.latestPlaceholder;
      const canClaim = !!getConnectedWalletAddress() && !viewerHasClaimed && !full && complete && canSubmitRewardClaims();
      const status = full ? 'claimed' : (complete ? 'open' : 'locked');
      const cardClass = getBountyCardClass(status);
      const progressPct = goal > 0 ? Math.min(100, Math.round((progress / goal) * 100)) : 0;
      const claimProgressPct = goal > 0 ? Math.min(100, Math.round((claimProgress / goal) * 100)) : 0;
      const pendingProgressPct = Math.max(0, progressPct - claimProgressPct);
      const showPendingVisual = hasPendingProgress && hasPendingSubmission;
      const stateLabel = full
        ? 'Closed'
        : viewerHasClaimed
          ? 'Claimed'
          : (complete ? 'Ready' : (pendingCompletion ? 'Finish Run' : (awaitingServerSync ? 'Syncing' : 'In Progress')));

      const namesMarkup = claimNames.length
        ? `<div class="bounty-claimant">Claimed by <strong>${claimNames.map((name) => escapeHtml(name)).join('</strong>, <strong>')}</strong></div>`
        : '<div class="bounty-claimant">No claims yet this week. Each wallet can claim a bounty once, and each bounty can only be claimed by 3 unique wallets.</div>';
      const buttonText = viewerHasClaimed
        ? 'Claimed'
        : full
          ? 'Closed'
          : pendingCompletion
            ? 'Finish Run to complete'
            : awaitingServerSync
              ? 'Syncing submitted run…'
              : complete
                ? `Claim ${escapeHtml(entry.reward || '0.0125 AVAX')}`
                : 'Keep Playing';
      const debugNote = '';
      const pendingHint = showPendingVisual
        ? '<div class="bounty-pending-note">Transparent progress will turn solid after the finishing run is submitted and accepted.</div>'
        : (awaitingServerSync
          ? `<div class="bounty-pending-note">Your finishing run was submitted. This bounty will unlock as soon as the server finishes syncing it.</div>${debugNote}`
          : (syncDebugState.latestPlaceholder && debugNote
            ? `<div class="bounty-pending-note">The newest server run is an empty follow-up run, so this card is no longer waiting on that placeholder.</div>${debugNote}`
            : ''));
      const submittingClaimMarkup = '<button type="button" class="bounty-claim-btn is-submitting" disabled><span class="bounty-claim-btn-inner"><span class="bounty-claim-spinner" aria-hidden="true"></span><span>Submitted</span></span></button>';
      const rewardButtons = [];
      if (Number(entry.rewardAvax || 0) > 0) {
        rewardButtons.push(`<button type="button" class="bounty-claim-btn" data-bounty-id="${escapeHtml(entry.id)}" data-reward-currency="AVAX" ${state.claiming ? 'disabled' : ''}>Claim ${escapeHtml(entry.rewardAvaxText || 'AVAX')}</button>`);
      }
      if (Number(entry.rewardRon || 0) > 0) {
        rewardButtons.push(`<button type="button" class="bounty-claim-btn${rewardButtons.length ? ' bounty-claim-btn-alt' : ''}" data-bounty-id="${escapeHtml(entry.id)}" data-reward-currency="RON" ${state.claiming ? 'disabled' : ''}>Claim ${escapeHtml(entry.rewardRonText || 'RON')}</button>`);
      }
      if (Number(entry.rewardJewel || 0) > 0) {
        rewardButtons.push(`<button type="button" class="bounty-claim-btn${rewardButtons.length ? ' bounty-claim-btn-alt' : ''}" data-bounty-id="${escapeHtml(entry.id)}" data-reward-currency="JEWEL" ${state.claiming ? 'disabled' : ''}>Claim ${escapeHtml(entry.rewardJewelText || 'JEWEL')}</button>`);
      }
      const claimActions = state.claiming
        ? submittingClaimMarkup
        : viewerHasClaimed
          ? '<button type="button" class="bounty-claim-btn" disabled>Claimed</button>'
          : (canClaim
            ? (rewardButtons.length
              ? `<div class="bounty-claim-actions">${rewardButtons.join('')}</div>`
              : '<button type="button" class="bounty-claim-btn" disabled>No reward configured</button>')
            : `<button type="button" class="bounty-claim-btn" data-bounty-id="${escapeHtml(entry.id)}" disabled>${escapeHtml(buttonText)}</button>`);
      return `
        <article class="bounty-card ${cardClass}${showPendingVisual ? ' has-pending-progress' : ''}">
          <div class="bounty-card-top">
            <div class="bounty-tier-wrap">
              <div class="bounty-tier-label">Weekly Bounty</div>
              <div class="bounty-tier-index">${index + 1}</div>
            </div>
            <div class="bounty-reward-pill ${cardClass}">${escapeHtml(entry.rewardPairText || entry.rewardText || entry.reward || '0.0005 AVAX, 0.0005 RON, or 5 JEWEL')}</div>
          </div>
          <h3 class="bounty-card-title">${escapeHtml(entry.title || 'Weekly Bounty')}</h3>
          <div class="bounty-progress-row">
            <div class="bounty-progress-copy">${progress.toLocaleString('en-US')} / ${goal.toLocaleString('en-US')}</div>
            <div class="bounty-progress-copy">${claimCount}/${claimLimit} claimed</div>
          </div>
          <div class="bounty-progress-bar${showPendingVisual ? ' is-pending-submission' : ''}" aria-hidden="true">
            <span class="bounty-progress-bar-solid" style="width:${showPendingVisual ? claimProgressPct : progressPct}%;"></span>
            ${showPendingVisual && pendingProgressPct > 0 ? `<span class="bounty-progress-bar-pending" style="left:${claimProgressPct}%;width:${pendingProgressPct}%;"></span>` : ''}
          </div>
          <div class="bounty-card-footer">
            <span class="bounty-state-chip ${cardClass}${pendingCompletion ? ' is-pending-submission' : ''}">${stateLabel}</span>
            <span class="bounty-chain-note">${escapeHtml(entry.categoryLabel || 'Weekly Challenge')} • ${escapeHtml(entry.metricLabel || 'Tracked progress')}</span>
          </div>
          ${namesMarkup}
          ${pendingHint}
          ${claimActions}
        </article>
      `;
    }).join('');
    const banner = state.error ? `<div class="bounty-status-banner is-error">${state.error}</div>` : '';
    const resetText = state.nextRevealAt
      ? `Weekly reset in ${formatBountyCountdown(state.nextRevealAt, new Date().toISOString())}`
      : 'Weekly reset every Monday 00:00 UTC';
    const showBountyTestReset = canUseBountyProgressTestReset(getConnectedWalletAddress());
    const hasBountyResetWalletInput = Object.prototype.hasOwnProperty.call(state, 'resetWalletInput');
    const resetBountyWalletValue = escapeHtml(String(hasBountyResetWalletInput ? (state.resetWalletInput || '') : ''));
    const testResetControls = showBountyTestReset
      ? `<div class="tracked-runs-hero-strip quests-summary-strip" style="margin-top:12px;">
          <div>
            <div class="bounty-strip-kicker">Private test controls</div>
            <p class="bounty-strip-copy">This reset button only appears for your wallet. It clears this week's bounty claim requests, claim slots, and tracked runs. You can also enter another wallet address to reset that wallet's weekly bounty state.</p>
          </div>
          <div style="display:flex;gap:8px;align-items:center;flex-wrap:wrap;justify-content:flex-end;">
            <input type="text" class="tracked-runs-search-input" data-reset-bounty-wallet-input="true" placeholder="0x wallet address" value="${resetBountyWalletValue}" style="max-width:260px;" spellcheck="false" autocomplete="off" ${state.resetting ? 'disabled' : ''} />
            <button type="button" class="small-action" data-reset-weekly-bounty-progress="true" ${state.resetting ? 'disabled' : ''}>${state.resetting ? 'Resetting…' : 'Reset weekly bounty progress'}</button>
          </div>
        </div>`
      : '';
    bountyTargetBody.innerHTML = `
      <div class="bounty-hero-strip">
        <div>
          <div class="bounty-strip-kicker">Seven weekly bounties roll every Monday</div>
          <p class="bounty-strip-copy">Seven weekly bounties roll every Monday: 3 light, 3 medium, and 1 heavy. Each bounty can be claimed by up to 3 unique wallets, each wallet can claim a given bounty once, and every claim must choose AVAX, RON, or JEWEL.</p>
          <p class="bounty-strip-copy bounty-strip-copy-subtle">Bounties cannot be claimed until the run that finishes them is over and successfully submitted. Transparent progress shows what you will be able to claim after that run is accepted.</p>
        </div>
        <div class="bounty-strip-badge">${resetText}</div>
      </div>
      ${banner}
      ${testResetControls}
      <div class="bounty-grid">${cards || '<div class="bounty-status-banner">No active weekly bounties found.</div>'}</div>
    `;
  }

  function startBountyCountdownTick() {

    if (game.bountyBoard.tickTimer) clearInterval(game.bountyBoard.tickTimer);
    game.bountyBoard.tickTimer = setInterval(() => {
      if (!els.bountyModal || els.bountyModal.classList.contains('hidden')) return;
      renderBountyBoard();
    }, 1000);
  }

  function stopBountyCountdownTick() {
    if (!game.bountyBoard.tickTimer) return;
    clearInterval(game.bountyBoard.tickTimer);
    game.bountyBoard.tickTimer = null;
  }

  async function refreshBountyBoard() {
    game.bountyBoard.loading = true;
    game.bountyBoard.error = '';
    game.bountyBoard.weekKey = getWeeklyBountyWeekKey();
    game.bountyBoard.entries = getClientWeeklyBountyEntries(game.bountyBoard.weekKey, Array.isArray(game.bountyBoard.entries) ? game.bountyBoard.entries : []);
    game.bountyBoard.nextRevealAt = nextWeekIso(game.bountyBoard.weekKey);
    renderBountyBoard();
    try {
      const walletAddress = getConnectedWalletAddress();
      const response = await callBountyFunction(BOUNTY_BOARD_FUNCTION, walletAddress ? { walletAddress, wallet_address: walletAddress, _ts: Date.now() } : { _ts: Date.now() });
      game.bountyBoard.entries = getClientWeeklyBountyEntries(game.bountyBoard.weekKey, Array.isArray(response.entries) ? response.entries : []);
      game.bountyBoard.runs = Array.isArray(response.runs) ? response.runs : [];
      game.bountyBoard.debug = response && response.debug && typeof response.debug === 'object' ? response.debug : null;
      game.bountyBoard.currentTimeIso = response.currentTime || new Date().toISOString();
      game.bountyBoard.nextRevealAt = response.nextRevealAt || nextWeekIso(game.bountyBoard.weekKey);
    } catch (error) {
      game.bountyBoard.entries = getClientWeeklyBountyEntries(game.bountyBoard.weekKey, []);
      game.bountyBoard.error = error && error.message ? error.message : 'Failed to load bounty board.';
    } finally {
      game.bountyBoard.loading = false;
      renderBountyBoard();
      renderTrackedRunsBoard();
    }
  }

  async function claimActiveBounty(bountyId = '', rewardCurrency = '') {
    const walletAddress = getConnectedWalletAddress();
    if (!walletAddress) {
      showBanner('Connect your wallet first.', 2200);
      return;
    }
    const activeLock = hydrateBountyClaimLockState(walletAddress);
    if (game.bountyBoard.claiming || activeLock) {
      showBanner('A bounty claim is already being processed. Please wait for it to finish.', 2400);
      renderBountyBoard();
      return;
    }
    const targetEntry = (Array.isArray(game.bountyBoard?.entries) ? game.bountyBoard.entries : []).find((entry) => String(entry && entry.id || '') === String(bountyId || '')) || null;
    const clientClaimId = `${Date.now()}-${Math.random().toString(36).slice(2, 10)}`;
    writeBountyClaimLock(walletAddress, { bountyId, rewardCurrency, clientClaimId });
    game.bountyBoard.claiming = true;
    game.bountyBoard.claimingBountyId = String(bountyId || '');
    game.bountyBoard.claimingRewardCurrency = String(rewardCurrency || '').toUpperCase();
    game.bountyBoard.claimingClientId = clientClaimId;
    game.bountyBoard.error = '';
    renderBountyBoard();
    let claimResult = null;
    let claimSucceeded = false;
    try {
      claimResult = await callBountyFunction(CLAIM_BOUNTY_FUNCTION, {
        walletAddress,
        bountyId,
        rewardCurrency,
        progressValue: targetEntry ? getWeeklyBountyClaimProgressValue(targetEntry) : 0,
        clientClaimId,
      }, true);
      claimSucceeded = true;
      showBanner(claimResult && claimResult.message ? claimResult.message : 'Bounty claimed.', 2600);
      if (claimResult && (String(claimResult.status || '').toLowerCase() === 'paid' || String(claimResult.txHash || '').trim())) {
        refreshWalletJewelTokenBalance({ skipMilestoneRender: true }).catch(() => null);
        if (typeof refreshTopMenuData === 'function') refreshTopMenuData({ includeRunBalance: false });
        showRewardPayoutNotice({
          txHash: claimResult.txHash,
          rewardText: String(claimResult.amountText || claimResult.rewardText || 'JEWEL').trim() || 'JEWEL',
          reasonText: claimResult.title || 'Bounty reward',
        });
      }
      try {
        await refreshBountyBoardWithRetry({ attempts: 3, delayMs: 700 });
      } catch (_refreshError) {
        game.bountyBoard.error = 'Claim submitted. Refreshing the board took too long, but your claim request was sent.';
        showBanner(game.bountyBoard.error, 3200);
      }
      if (window.DFKRunTracker && typeof window.DFKRunTracker.refreshSummary === 'function') {
        window.DFKRunTracker.refreshSummary().catch(() => {});
      }
    } catch (error) {
      const baseMessage = error && error.message ? error.message : 'Bounty claim failed.';
      const progress = Number(error && error.progress);
      const goal = Number(error && error.goal);
      const progressMessage = Number.isFinite(progress) && Number.isFinite(goal) && goal > 0
        ? `${baseMessage} Server progress: ${progress.toLocaleString('en-US')} / ${goal.toLocaleString('en-US')}.`
        : baseMessage;
      game.bountyBoard.error = progressMessage;
      showBanner(progressMessage, 3200);
      renderBountyBoard();
    } finally {
      clearBountyClaimLock(walletAddress);
      game.bountyBoard.claiming = false;
      game.bountyBoard.claimingBountyId = '';
      game.bountyBoard.claimingRewardCurrency = '';
      game.bountyBoard.claimingClientId = '';
      if (claimSucceeded && claimResult && String(claimResult.status || '').toLowerCase() === 'pending') {
        setTimeout(() => { refreshBountyBoard().catch(() => {}); }, 1200);
      }
      renderBountyBoard();
      renderTrackedRunsBoard();
    }
  }



  function clearWalletSpecificBountyAndTrackingState(walletAddress = '') {
    const normalizedWallet = normalizeAddress(walletAddress || getConnectedWalletAddress() || '');
    if (!normalizedWallet) return;
    const activeWeekKey = String((game.bountyBoard && game.bountyBoard.weekKey) || getWeeklyBountyWeekKey());
    try {
      localStorage.removeItem(getWeeklyBountyStorageKey(normalizedWallet, activeWeekKey));
    } catch (_error) {}
    clearRecentTrackedRunSubmission(normalizedWallet);
    if (game.weeklyBountyProgress && normalizeAddress(game.weeklyBountyProgress.playerKey) === normalizedWallet) {
      game.weeklyBountyProgress = {
        playerKey: normalizedWallet,
        weekKey: activeWeekKey,
        metrics: createEmptyWeeklyBountyMetrics(),
        dirtySessionMetrics: false,
      };
    }
    if (!game.bountyBoard || typeof game.bountyBoard !== 'object') game.bountyBoard = {};
    game.bountyBoard.entries = [];
    game.bountyBoard.error = '';
    game.bountyBoard.runs = [];
    game.bountyBoard.weekKey = activeWeekKey;
    if (window.DFKRunTracker && typeof window.DFKRunTracker.clearWalletQueueState === 'function') {
      try {
        window.DFKRunTracker.clearWalletQueueState(normalizedWallet);
      } catch (_error) {}
    }
  }

  async function resetWeeklyBountyProgressForTestWallet(targetWalletAddress = '') {
    if (game.bountyBoard.resetting) return;
    const adminWallet = getConnectedWalletAddress();
    if (!adminWallet || !canUseBountyProgressTestReset(adminWallet)) {
      showBanner('This reset control is only enabled for the private test wallet.', 2800);
      return;
    }
    const targetWallet = normalizeAddress(targetWalletAddress || game.bountyBoard.resetWalletInput || adminWallet);
    if (!isLikelyWalletAddress(targetWallet)) {
      showBanner('Enter a valid wallet address to reset.', 2800);
      return;
    }
    game.bountyBoard.resetting = true;
    game.bountyBoard.error = '';
    game.bountyBoard.resetWalletInput = targetWallet;
    renderBountyBoard();
    try {
      const result = await callBountyFunction(BOUNTY_RESET_PROGRESS_FUNCTION, { walletAddress: targetWallet }, true);
      const deletedRuns = Math.max(0, Number(result && result.deletedRuns || 0) || 0);
      const deletedClaims = Math.max(0, Number(result && result.deletedClaimRequests || 0) || 0);
      const deletedWeeklyClaims = Math.max(0, Number(result && result.deletedWeeklyClaims || 0) || 0);
      const message = result && result.message
        ? result.message
        : `Weekly bounty progress reset for ${targetWallet}. Removed ${deletedRuns} run${deletedRuns === 1 ? '' : 's'}, ${deletedClaims} claim request${deletedClaims === 1 ? '' : 's'}, and ${deletedWeeklyClaims} weekly claim slot${deletedWeeklyClaims === 1 ? '' : 's'}.`;
      clearWalletSpecificBountyAndTrackingState(targetWallet);
      showBanner(message, 4200);
      await refreshBountyBoard();
      if (window.DFKRunTracker && typeof window.DFKRunTracker.refreshSummary === 'function') {
        window.DFKRunTracker.refreshSummary().catch(() => {});
      }
    } catch (error) {
      const message = error && error.message ? error.message : 'Failed to reset weekly bounty progress.';
      game.bountyBoard.error = message;
      showBanner(message, 3600);
      renderBountyBoard();
    } finally {
      game.bountyBoard.resetting = false;
      renderBountyBoard();
      renderTrackedRunsBoard();
    }
  }



  function getEliteWaveSummary(plan) {
    if (!plan?.eliteConfig) return '';
    const cfg = plan.eliteConfig;
    const parts = [];
    if (cfg.enemyMult) parts.push(`${Math.round((cfg.enemyMult - 1) * 100)}% more enemies`);
    if (cfg.extraBosses) parts.push(`${cfg.extraBosses} extra boss${cfg.extraBosses === 1 ? '' : 'es'}`);
    if (cfg.skitters) parts.push(`${cfg.skitters} elite skitters` + (cfg.skitterBursts && cfg.skitterBursts > 1 ? ` in ${cfg.skitterBursts} bursts` : ''));
    if (cfg.finalSkyTerror) parts.push('a flying siege terror appears after the wave is cleared');
    return parts.join(' • ');
  }

  function shakeEliteWaveWarning() {
    document.body.classList.remove('elite-wave-shake');
    void document.body.offsetWidth;
    document.body.classList.add('elite-wave-shake');
    setTimeout(() => document.body.classList.remove('elite-wave-shake'), 100);
  }

  function openEliteWaveModal(plan) {
    if (!els.eliteWaveModal || !els.eliteWaveBody || !plan?.elite) return;
    const summary = getEliteWaveSummary(plan);
    els.eliteWaveBody.innerHTML = `<div class="elite-wave-kicker">Elite Waves hit harder than standard waves.</div><h3 class="elite-wave-title">Elite Wave ${plan.waveNumber} Approaching</h3><p class="elite-wave-copy">Prepare yourself before you start this wave.</p><div class="elite-wave-summary">${summary || 'This wave has extra pressure.'}</div>`;
    els.eliteWaveModal.classList.remove('hidden');
    els.eliteWaveModal.setAttribute('aria-hidden', 'false');
    shakeEliteWaveWarning();
  }

  function closeEliteWaveModal() {
    if (!els.eliteWaveModal) return;
    els.eliteWaveModal.classList.add('hidden');
    els.eliteWaveModal.setAttribute('aria-hidden', 'true');
  }

  function maybeShowEliteWaveWarning(plan) {
    if (!plan || !plan.elite) return;
    const rarePool = RELICS.filter((relic) => relic && ['rare', 'legendary', 'mythic'].includes(String(relic.rarity || '').toLowerCase()));
    const teaser = rarePool.length ? rarePool[Math.floor(Math.random() * rarePool.length)] : null;
    const teaserLabel = teaser ? teaser.name : 'a rare or better relic';
    showBanner(`Elite wave coming — scoop ${teaserLabel} for 1 Jewel?`, 3200);
  }

  function openKnownRelicsModal() {
    if (!els.knownRelicsModal || !els.knownRelicsBody) return;
    closeQuestsModal();
    const commonAndRare = RELICS.filter(r => ['common', 'rare'].includes(r.rarity || 'common'));
    const legendaryRelics = RELICS.filter(r => (r.rarity || 'common') === 'legendary');
    const mythicRelics = RELICS.filter(r => (r.rarity || 'common') === 'mythic');
    const persistentKnownRelicIds = syncPersistentKnownRelics();
    const revealedLegendary = legendaryRelics.filter(r => persistentKnownRelicIds.includes(r.id));
    const revealedMythic = mythicRelics.filter(r => persistentKnownRelicIds.includes(r.id));
    const hiddenLegendaryCount = Math.max(0, legendaryRelics.length - revealedLegendary.length);
    const hiddenMythicCount = Math.max(0, mythicRelics.length - revealedMythic.length);
    const foundRelics = (Array.isArray(game.foundRelics) ? game.foundRelics : []).map(id => RELICS.find(r => r.id === id)).filter(Boolean);
    const foundSection = foundRelics.length
      ? `<section class="known-relic-section"><div class="known-relic-heading known-relic-heading-found">Found This Game (${foundRelics.length}/${RELICS.length})</div><div class="known-relic-found-list">${foundRelics.map(r => { const rarity = getRelicRarity(r); return `<span class=\"relic-pill ${rarity.className}\" title=\"${r.desc}\">${r.name} (${getRelicCostLabel(r)})</span>`; }).join(' ')}</div></section>`
      : `<section class="known-relic-section"><div class="known-relic-heading known-relic-heading-found">Found This Game (0/${RELICS.length})</div><article class="known-relic-card known-relic-found-empty"><p>No relics found yet in this run.</p></article></section>`;
    const sections = ['common', 'rare'].map(key => {
      const rarity = RELIC_RARITY_META[key];
      const items = commonAndRare.filter(r => (r.rarity || 'common') === key);
      if (!items.length) return '';
      return `<section class="known-relic-section"><div class="known-relic-heading ${rarity.className}">${rarity.label} Relics</div>${items.map(r => `<article class=\"known-relic-card ${rarity.className}\"><h4>${r.name}</h4><p class=\"gold\">${getRelicCostLabel(r)}</p><p>${r.desc}</p></article>`).join('')}</section>`;
    }).join('');
    const legendarySection = legendaryRelics.length
      ? `<section class="known-relic-section"><div class="known-relic-heading relic-rarity-legendary">Legendary Relics</div>${revealedLegendary.map(r => `<article class="known-relic-card relic-rarity-legendary"><h4>${r.name}</h4><p class="gold">${getRelicCostLabel(r)}</p><p>${r.desc}</p></article>`).join('')}${hiddenLegendaryCount ? `<article class="known-relic-card relic-rarity-legendary relic-hidden-card"><h4>????</h4><p>${hiddenLegendaryCount === 1 ? 'One legendary relic remains hidden.' : `${hiddenLegendaryCount} legendary relics remain hidden.`}</p></article>` : ''}</section>`
      : '';
    const mythicSection = mythicRelics.length
      ? `<section class="known-relic-section"><div class="known-relic-heading relic-rarity-mythic">Mythic</div>${revealedMythic.map(r => `<article class="known-relic-card relic-rarity-mythic"><h4>${r.name}</h4><p class="gold">${getRelicCostLabel(r)}</p><p>${r.desc}</p></article>`).join('')}${hiddenMythicCount ? `<article class="known-relic-card relic-rarity-mythic relic-hidden-card"><h4>????</h4><p>${hiddenMythicCount === 1 ? 'One mythic relic remains hidden.' : `${hiddenMythicCount} mythic relics remain hidden.`}</p></article>` : ''}</section>`
      : '';
    els.knownRelicsBody.innerHTML = `${foundSection}${sections}${legendarySection}${mythicSection}`;
    els.knownRelicsModal.classList.remove('hidden');
    els.knownRelicsModal.setAttribute('aria-hidden', 'false');
  }

  function closeKnownRelicsModal() {
    if (!els.knownRelicsModal) return;
    els.knownRelicsModal.classList.add('hidden');
    els.knownRelicsModal.setAttribute('aria-hidden', 'true');
  }

