  const WALLET_HERO_CHAIN_CONFIGS = Object.freeze([
    { key: 'dfk', chainId: DFK_CHAIN_ID, name: 'DFK Chain', heroAddress: DFK_HERO_CORE_ADDRESS, rpcUrl: DFK_CHAIN_RPC_URL, rpcUrls: DFK_CHAIN_RPC_FALLBACKS, transferSupported: true },
    { key: 'metis', chainId: METIS_CHAIN_ID, name: 'Metis', heroAddress: METIS_HERO_CORE_ADDRESS, rpcUrl: METIS_CHAIN_RPC_URL, transferSupported: false },
    { key: 'ronin', chainId: RONIN_CHAIN_ID, name: 'Ronin', heroAddress: AXIE_CONTRACT_ADDRESS, rpcUrl: RONIN_CHAIN_RPC_URL, rpcUrls: RONIN_CHAIN_RPC_FALLBACKS, transferSupported: false },
  ]);

  function getWalletRpcProvider() {
    return window.DFKDefenseWallet && typeof window.DFKDefenseWallet.getProvider === 'function'
      ? window.DFKDefenseWallet.getProvider()
      : null;
  }

  function getWalletHeroChainConfig(value) {
    const key = String(value || '').trim().toLowerCase();
    if (!key) return null;
    return WALLET_HERO_CHAIN_CONFIGS.find((entry) => entry.key === key || String(entry.chainId) === key) || null;
  }

  function getWalletHeroImageId(heroLike) {
    const normalized = heroLike && heroLike.normalizedId != null ? String(heroLike.normalizedId).trim() : '';
    const raw = heroLike && heroLike.id != null ? String(heroLike.id).trim() : '';
    return normalized || raw;
  }

  function getWalletHeroNumericId(heroLike) {
    const raw = getWalletHeroImageId(heroLike);
    const parsed = Number(raw);
    return Number.isFinite(parsed) ? parsed : Number.MAX_SAFE_INTEGER;
  }

  function getWalletHeroChainName(heroLike) {
    const config = getWalletHeroChainConfig(heroLike && (heroLike.chainKey || heroLike.chainId));
    return config ? config.name : 'Wallet';
  }

  function getWalletHeroSourceBadge(heroLike) {
    const config = getWalletHeroChainConfig(heroLike && (heroLike.chainKey || heroLike.chainId));
    return config ? config.name : 'Wallet';
  }

  function getAxieClassKey(axieLike) {
    const raw = String(axieLike?.class || axieLike?.axieClass || axieLike?.className || '').trim().toLowerCase();
    return AXIE_CLASS_TO_PET_BONUS[raw] ? raw : 'unknown';
  }

  function getAxiePetBonus(axieLike) {
    return AXIE_CLASS_TO_PET_BONUS[getAxieClassKey(axieLike)] || AXIE_CLASS_TO_PET_BONUS.unknown;
  }

  function getAxieImage(axieLike) {
    const imageUrl = normalizeHeroMediaUrl(axieLike?.imageUrl || axieLike?.image || axieLike?.mediaUrl || '');
    if (imageUrl) return imageUrl;
    const id = String(axieLike?.id || axieLike?.tokenId || '').trim();
    return id ? `https://axiecdn.axieinfinity.com/axies/${encodeURIComponent(id)}/axie/axie-full-transparent.png` : 'assets/placeholder-monk.png';
  }

  function getSelectedAxiePet(type) {
    const selectedId = game.selectedAxiePets ? game.selectedAxiePets[type] : null;
    if (!selectedId) return null;
    return (game.walletAxieRoster || []).find((axie) => String(axie.id) === String(selectedId)) || null;
  }

  function getTowerAxiePetDisplay(tower) {
    if (!tower || tower.isSatellite || tower.isChampion || isStatueTower(tower)) return null;
    if (tower.axiePetApplied && tower.axiePetImageUrl) {
      return {
        id: tower.axiePetId || '',
        imageUrl: tower.axiePetImageUrl,
        label: tower.axiePetLabel || 'Companion',
      };
    }
    const selectedAxie = getSelectedAxiePet(tower.type);
    if (!selectedAxie) return null;
    return {
      id: String(selectedAxie.id || selectedAxie.tokenId || ''),
      imageUrl: getAxieImage(selectedAxie),
      label: getAxiePetBonus(selectedAxie).label || 'Companion',
    };
  }

  function selectAxiePet(type, axieId) {
    if (!type || !axieId) return;
    if (!game.selectedAxiePets || typeof game.selectedAxiePets !== 'object') game.selectedAxiePets = {};
    for (const [assignedType, assignedId] of Object.entries(game.selectedAxiePets)) {
      if (assignedType !== type && String(assignedId) === String(axieId)) delete game.selectedAxiePets[assignedType];
    }
    game.selectedAxiePets[type] = String(axieId);
    renderWalletHeroBonusPanel();
    renderHirePanel();
  }

  function applyAxiePetToTower(tower, axieLike) {
    if (!tower || !axieLike || tower.axiePetApplied || tower.isSatellite || tower.isChampion) return false;
    const bonus = getAxiePetBonus(axieLike);
    const previousMaxHp = Number(tower.maxHp || 0);
    const previousHp = Number(tower.hp || 0);
    tower.axiePetApplied = true;
    tower.axiePetId = String(axieLike.id || axieLike.tokenId || '');
    tower.axiePetClass = getAxieClassKey(axieLike);
    tower.axiePetLabel = bonus.label;
    tower.axiePetImageUrl = getAxieImage(axieLike);
    tower.axiePetDamageMult = Number(bonus.damageMult || 1);
    tower.axiePetHpMult = Number(bonus.hpMult || 1);
    tower.axiePetSpeedMult = Number(bonus.speedMult || 1);
    if (Number(bonus.damageMult || 1) !== 1) {
      tower.damage = Math.max(0, Number(tower.damage || 0)) * Number(bonus.damageMult || 1);
      tower.baseDamage = Math.max(0, Number(tower.baseDamage || tower.damage || 0)) * Number(bonus.damageMult || 1);
    }
    if (Number(bonus.hpMult || 1) !== 1) {
      tower.maxHp = Math.max(1, Math.round(Number(tower.maxHp || 1) * Number(bonus.hpMult || 1)));
      tower.hp = Math.min(tower.maxHp, Math.max(1, Math.round(Number(tower.hp || tower.maxHp || 1) * Number(bonus.hpMult || 1))));
      if (Number.isFinite(previousHp) && previousHp > 0 && Number.isFinite(previousMaxHp) && previousMaxHp > 0) {
        const hpRatio = Math.max(0, Math.min(1, previousHp / previousMaxHp));
        tower.hp = Math.max(1, Math.min(tower.maxHp, tower.maxHp * hpRatio));
      }
    }
    if (Number(bonus.speedMult || 1) !== 1 && Number(tower.basicCooldown || 0) > 0) {
      tower.basicCooldown = Math.max(80, Number(tower.basicCooldown || 0) / Number(bonus.speedMult || 1));
    }
    tower.reportLabel = (tower.reportLabel || tower.name || 'Hero') + ` • Axie #${tower.axiePetId}`;
    return true;
  }

  function isGen0WalletHero(heroLike) {
    if (!heroLike) return false;
    const override = getKnownHeroGen0Override(heroLike.id || heroLike.normalizedId || heroLike.heroId);
    if (override != null) return override === true;
    const chainKey = normalizeWalletHeroNetwork(heroLike.chainKey || heroLike.chainId || heroLike.network);
    if (chainKey === 'metis') {
      // Metis heroes do not expose the same reliable generation field as DFK Chain heroes.
      // Only the explicit chain-read flag should grant Gen0 UI or combat bonus; never infer
      // Gen0 from a cached/display influence string, because that caused false positives.
      return heroLike.isGen0 === true && String(heroLike.gen0Source || '').startsWith('getHeroInfluenceData');
    }
    if (heroLike.isGen0 === true) return true;
    const generation = Number(heroLike.generation);
    return Number.isFinite(generation) && generation === 0;
  }

  function getWalletHeroGenerationBadge(heroLike) {
    return isGen0WalletHero(heroLike) ? 'Gen 0' : '';
  }

  function getWalletHeroBonusEligibilityText(heroLike) {
    return isGen0WalletHero(heroLike) ? 'Gen0 bonus eligible' : '';
  }

  function getWalletHeroLineParts(heroLike, extraParts = []) {
    const parts = [getWalletHeroSourceBadge(heroLike)];
    if (isGen0WalletHero(heroLike)) parts.push(getWalletHeroGenerationBadge(heroLike), getWalletHeroBonusEligibilityText(heroLike));
    for (const part of extraParts) {
      const text = String(part || '').trim();
      if (text) parts.push(text);
    }
    return parts.filter(Boolean);
  }

  function isGen0BonusTower(tower) {
    return !!(tower
      && tower.walletHeroGen0Bonus === true
      && !tower.isChampion
      && !String(tower.type || '').startsWith('champion_'));
  }

  function getWalletHeroById(id) {
    const target = String(id || '').trim();
    if (!target) return null;
    const rosters = [game.walletHeroRoster, game.allWalletHeroRoster].filter(Array.isArray);
    for (const roster of rosters) {
      const hero = roster.find((entry) => entry && (String(entry.id || '') === target || String(entry.normalizedId || '') === target || String(entry.rawId || '') === target));
      if (hero) return hero;
    }
    return null;
  }

  function getSelectedGen0WalletHeroCount() {
    try {
      return Object.values(game.selectedWalletHeroes || {}).filter((heroId) => isGen0WalletHero(getWalletHeroById(heroId))).length;
    } catch (error) {
      console.warn('[gen0-ui] selected Gen0 count failed', error);
      return 0;
    }
  }

  function normalizeHeroTypeKey(type) {
    return String(type || '').trim().toLowerCase();
  }

  function activateGen0ClassForType(type) {
    const key = normalizeHeroTypeKey(type);
    if (!key || String(key).startsWith('champion_')) return;
    if (!game.gen0ClassActive || typeof game.gen0ClassActive !== 'object') game.gen0ClassActive = {};
    const wasActive = !!game.gen0ClassActive[key];
    game.gen0ClassActive[key] = true;
    if (!wasActive) {
      try { showBanner('GEN0 ACTIVE: ' + getGen0ClassDisplayName(key), 1800); } catch (error) {}
    }
  }

  function isGen0ClassActive(type) {
    const key = normalizeHeroTypeKey(type);
    return !!(key && game.gen0ClassActive && game.gen0ClassActive[key]);
  }

  function getGen0HeroButtonMode(type, selectedWalletHero = null, usesBonus = false) {
    if (usesBonus && isGen0ClassActive(type)) return 'inherited';
    if (selectedWalletHero && isGen0WalletHero(selectedWalletHero)) return 'selected';
    if (isGen0ClassActive(type)) return 'inherited';
    return '';
  }

  function getActiveGen0ClassCount() {
    return Object.values(game.gen0ClassActive || {}).filter(Boolean).length;
  }

  function getGen0BuffInfoMarkup(tower) {
    try {
      const hasActiveBuff = isGen0BonusTower(tower);
      if (!hasActiveBuff) return '';
      const title = 'GEN0 BUFF ACTIVE';
      const detail = '+20% damage • +10% attack speed • +10% max HP • +30% healing power';
      return '<div class="selected-info-gen0-buff"><strong>' + title + '</strong><span>' + escapeHtml(detail) + '</span></div>';
    } catch (error) {
      console.warn('[gen0-ui] failed to render buff info', error);
      return '';
    }
  }

  function getAxiePetInfoMarkup(tower) {
    try {
      if (!tower) return '';
      const displayPet = getTowerAxiePetDisplay(tower);
      if (!displayPet) return '';
      const fallbackAxie = tower.axiePetApplied ? null : getSelectedAxiePet(tower.type);
      const fallbackBonus = fallbackAxie ? getAxiePetBonus(fallbackAxie) : null;
      const bonusParts = [];
      const damagePct = Math.round((Number(tower.axiePetDamageMult || fallbackBonus?.damageMult || 1) - 1) * 100);
      const hpPct = Math.round((Number(tower.axiePetHpMult || fallbackBonus?.hpMult || 1) - 1) * 100);
      const speedPct = Math.round((Number(tower.axiePetSpeedMult || fallbackBonus?.speedMult || 1) - 1) * 100);
      if (damagePct > 0) bonusParts.push(`+${damagePct}% damage`);
      if (hpPct > 0) bonusParts.push(`+${hpPct}% max HP`);
      if (speedPct > 0) bonusParts.push(`+${speedPct}% attack speed`);
      const detail = bonusParts.length ? bonusParts.join(', ') : 'Companion bonus active';
      return '<div class="selected-info-rarity-buff selected-info-axie-pet"><strong>AXIE PET ACTIVE</strong><span>' + escapeHtml(`Axie #${displayPet.id || '?'} - ${displayPet.label || 'Companion'} - ${detail}`) + '</span></div>';
    } catch (error) {
      console.warn('[axie-pet-ui] failed to render pet info', error);
      return '';
    }
  }

  function getRarityBuffInfoMarkup(tower) {
    try {
      if (!tower || Number(tower.walletHeroRarityBonus || 0) <= 0) return '';
      const rarityName = String(tower.walletHeroRarityName || getDfKRarityName(tower.walletHeroRarity) || 'Rarity').trim();
      const percent = Math.round(Number(tower.walletHeroRarityBonus || 0) * 100);
      return '<div class="selected-info-rarity-buff"><strong>' + escapeHtml(rarityName.toUpperCase()) + ' RARITY BUFF ACTIVE</strong><span>+' + percent + '% damage and max HP from this hero NFT.</span></div>';
    } catch (error) {
      console.warn('[rarity-ui] failed to render buff info', error);
      return '';
    }
  }

  function getChampionRarityChipMarkup(heroLike) {
    const rarityName = String(heroLike?.rarityName || getDfKRarityName(heroLike?.rarity) || 'Common').trim();
    const key = rarityName.toLowerCase();
    const safeKey = ['uncommon', 'rare', 'legendary', 'mythic'].includes(key) ? key : 'common';
    const bonus = getWalletHeroRarityCombatBonus(heroLike, { includeGen0: true });
    const bonusText = bonus > 0 ? '+' + Math.round(bonus * 100) + '% DMG/HP' : 'No rarity bonus';
    return '<span class="champion-rarity-badge champion-rarity-' + safeKey + '"><span class="champion-rarity-name">' + escapeHtml(rarityName || 'Common') + '</span><span class="champion-rarity-bonus">' + escapeHtml(bonusText) + '</span></span>';
  }

  function getChampionRarityRowMarkup(heroLike) {
    return '<div class="champion-rarity-row">' + getChampionRarityChipMarkup(heroLike) + '</div>';
  }

  function getActiveGen0ClassNames() {
    const active = game.gen0ClassActive && typeof game.gen0ClassActive === 'object' ? game.gen0ClassActive : {};
    return Object.keys(active)
      .filter((key) => active[key])
      .map((key) => String(key || '').trim().toLowerCase())
      .filter(Boolean)
      .sort();
  }

  function getGen0ClassDisplayName(type) {
    const key = normalizeHeroTypeKey(type);
    const labels = {
      warrior: 'Warrior',
      archer: 'Archer',
      wizard: 'Wizard',
      priest: 'Priest',
      pirate: 'Pirate',
      seer: 'Seer',
      monk: 'Monk',
      berserker: 'Berserker',
    };
    return labels[key] || (key ? key.charAt(0).toUpperCase() + key.slice(1) : 'Hero');
  }

  function ensureGen0ActiveBannerEl() {
    let el = document.getElementById('gen0ActiveBanner');
    if (!el) {
      el = document.createElement('div');
      el.id = 'gen0ActiveBanner';
      el.className = 'gen0-active-banner hidden';
      el.setAttribute('aria-live', 'polite');
      el.innerHTML = '<div class="gen0-active-banner-title">GEN0 ACTIVE</div><div class="gen0-active-banner-classes"></div><div class="gen0-active-banner-bonus">+20% DMG • +10% SPEED • +10% LIFE • +30% HEALING</div>';
    }

    const target = els.walletHeroBonusToggle || els.walletHeroBonusSection || document.body;
    if (target && el.parentNode !== target) target.appendChild(el);
    return el;
  }

  function renderGen0ActiveBanner() {
    const el = ensureGen0ActiveBannerEl();
    const activeClasses = getActiveGen0ClassNames();
    const shouldShow = activeClasses.length > 0 && game.phase !== SETUP_PHASES.GAME_OVER;
    el.classList.toggle('hidden', !shouldShow);
    if (els.walletHeroBonusSection) els.walletHeroBonusSection.classList.toggle('has-gen0-active-banner', shouldShow);
    if (!shouldShow) return;
    const classText = activeClasses.map(getGen0ClassDisplayName).join(' • ');
    const classEl = el.querySelector('.gen0-active-banner-classes');
    if (classEl) classEl.textContent = classText;
    el.title = 'Gen0 class buff is active this run. Future hires in listed classes inherit the Gen0 bonus.';
  }

  function applyGen0CombatBonusToTower(tower, source = 'wallet') {
    if (!tower || tower.gen0CombatBonusApplied) return false;
    if (tower.isChampion || String(tower.type || '').startsWith('champion_')) return false;
    const previousMaxHp = Number(tower.maxHp || 0);
    const previousHp = Number(tower.hp || 0);
    tower.walletHeroGen0Bonus = true;
    tower.walletHeroIsGen0 = true;
    tower.gen0CombatBonusApplied = true;
    tower.gen0BonusSource = source;
    if (tower.type === 'archer') {
      normalizeArcherStats(tower);
    } else {
      tower.damage = Math.max(0, Number(tower.damage || 0)) * GEN0_WALLET_HERO_DAMAGE_MULTIPLIER;
      tower.baseDamage = Math.max(0, Number(tower.baseDamage || tower.damage || 0)) * GEN0_WALLET_HERO_DAMAGE_MULTIPLIER;
      tower.maxHp = Math.max(1, Math.round(Number(tower.maxHp || 1) * GEN0_WALLET_HERO_HP_MULTIPLIER));
      tower.hp = Math.min(tower.maxHp, Math.max(1, Math.round(Number(tower.hp || tower.maxHp || 1) * GEN0_WALLET_HERO_HP_MULTIPLIER)));
      if (Number(tower.basicCooldown || 0) > 0) tower.basicCooldown = Math.max(80, Number(tower.basicCooldown || 0) / GEN0_WALLET_HERO_SPEED_MULTIPLIER);
    }
    if (tower.type === 'archer' && Number.isFinite(previousHp) && previousHp > 0 && Number.isFinite(previousMaxHp) && previousMaxHp > 0) {
      const hpRatio = Math.max(0, Math.min(1, previousHp / previousMaxHp));
      tower.hp = Math.max(1, Math.min(tower.maxHp, tower.maxHp * hpRatio));
    }
    tower.healingPowerMultiplier = Math.max(Number(tower.healingPowerMultiplier || 1), GEN0_WALLET_HERO_HEALING_MULTIPLIER);
    if (!String(tower.reportLabel || '').includes('Gen0')) tower.reportLabel = (tower.reportLabel || tower.name || 'Hero') + ' • Gen0';
    return true;
  }

  function applyGen0WalletHeroCombatBonus(tower, heroData) {
    if (!tower || !heroData || !isGen0WalletHero(heroData)) return;
    activateGen0ClassForType(tower.type || heroData.type);
    applyGen0CombatBonusToTower(tower, 'wallet');
  }

  function applyInheritedGen0ClassBonus(tower) {
    if (!tower || tower.isSatellite) return false;
    if (!isGen0ClassActive(tower.type)) return false;
    return applyGen0CombatBonusToTower(tower, 'class');
  }

  function normalizeWalletHeroRecord(heroLike, overrides = {}) {
    const next = { ...heroLike, ...overrides };
    const config = getWalletHeroChainConfig(next.chainKey || next.chainId || next.network);
    const chainKey = config ? config.key : String(next.chainKey || '').trim().toLowerCase();
    const normalizedId = next.normalizedId != null ? String(next.normalizedId).trim() : '';
    const rawId = next.id != null ? String(next.id).trim() : '';
    return {
      ...next,
      id: normalizedId || rawId,
      rawId: rawId || normalizedId,
      normalizedId: normalizedId || rawId,
      chainKey,
      chainId: config ? config.chainId : next.chainId,
      chainName: config ? config.name : (next.chainName || 'Wallet'),
      transferSupported: config ? !!config.transferSupported : !!next.transferSupported,
      rarity: Number.isFinite(Number(next.rarity)) ? Number(next.rarity) : (Number.isFinite(Number(next.rarity_id)) ? Number(next.rarity_id) : null),
      rarityName: String(next.rarityName || next.rarity_name || (Number.isFinite(Number(next.rarity)) ? getDfKRarityName(Number(next.rarity)) : '')).trim(),
      imageUrl: normalizeHeroMediaUrl(next.imageUrl) || `https://heroes.defikingdoms.com/image/${encodeURIComponent(normalizedId || rawId)}`,
    };
  }

  function normalizeWalletAxieRecord(axieLike, overrides = {}) {
    const next = { ...axieLike, ...overrides };
    const id = String(next.id ?? next.tokenId ?? next.axieId ?? '').trim();
    if (!id) return null;
    const axieClass = String(next.class || next.axieClass || next.className || '').trim();
    return {
      ...next,
      id,
      tokenId: id,
      normalizedId: id,
      chainKey: 'ronin',
      chainId: RONIN_CHAIN_ID,
      chainName: 'Ronin',
      collection: 'Axie Infinity',
      name: String(next.name || `Axie #${id}`),
      class: axieClass || 'Unknown',
      axieClass: axieClass || 'Unknown',
      imageUrl: getAxieImage({ ...next, id }),
      source: next.source || 'ronin',
    };
  }

  function commitWalletAxieList(axieList) {
    const axiesById = new Map();
    for (const rawAxie of Array.isArray(axieList) ? axieList : []) {
      const axie = normalizeWalletAxieRecord(rawAxie);
      if (axie) axiesById.set(String(axie.id), axie);
    }
    game.walletAxieRoster = Array.from(axiesById.values()).sort((a, b) => {
      const classDelta = getAxieClassKey(a).localeCompare(getAxieClassKey(b));
      if (classDelta !== 0) return classDelta;
      return getWalletHeroNumericId(a) - getWalletHeroNumericId(b);
    });
    const nextSelection = { ...(game.selectedAxiePets || {}) };
    const usedAxieIds = new Set();
    for (const type of DFK_SLOT_ORDER) {
      const existing = nextSelection[type] && game.walletAxieRoster.find((axie) => String(axie.id) === String(nextSelection[type]));
      if (existing && !usedAxieIds.has(String(existing.id))) {
        nextSelection[type] = String(existing.id);
        usedAxieIds.add(String(existing.id));
        continue;
      }
      if (existing) delete nextSelection[type];
      const nextAxie = game.walletAxieRoster.find((axie) => !usedAxieIds.has(String(axie.id)));
      if (nextAxie) {
        nextSelection[type] = String(nextAxie.id);
        usedAxieIds.add(String(nextAxie.id));
      }
    }
    game.selectedAxiePets = nextSelection;
    return game.walletAxieRoster.length;
  }

  function normalizeWalletHeroNetwork(value) {
    const raw = String(value || '').trim().toLowerCase();
    if (!raw) return '';
    if (
      raw === 'met' ||
      raw === 'metis' ||
      raw === 'cv' ||
      raw.includes('crystal') ||
      raw.includes('colosseum') ||
      raw.includes('andromeda')
    ) return 'metis';
    if (raw === 'ronin' || raw === 'ron' || raw === String(RONIN_CHAIN_ID) || raw.includes('axie')) return 'ronin';
    if (
      raw === 'dfk' ||
      raw === 'dfk chain' ||
      raw.includes('defi kingdoms chain') ||
      raw.includes('subnet')
    ) return 'dfk';
    if (raw === 'kla' || raw === 'kaia' || raw.includes('ser2')) return 'kaia';
    if (raw === 'hmy' || raw === 'harmony' || raw.includes('ser1') || raw === 'ser') return 'harmony';
    return raw;
  }

  function getWalletHeroRarityRank(heroLike) {
    if (!heroLike) return -1;
    const numeric = Number(heroLike.rarity);
    if (Number.isFinite(numeric)) return numeric;
    const name = String(heroLike.rarityName || heroLike.rarity_name || '').trim().toLowerCase();
    if (name === 'mythic') return 4;
    if (name === 'legendary') return 3;
    if (name === 'rare') return 2;
    if (name === 'uncommon') return 1;
    if (name === 'common') return 0;
    return -1;
  }

  function getWalletHeroRarityCombatBonus(heroLike, options = {}) {
    if (!heroLike || (!options.includeGen0 && isGen0WalletHero(heroLike))) return 0;
    const rank = getWalletHeroRarityRank(heroLike);
    if (rank >= 4) return 0.20;
    if (rank === 3) return 0.15;
    if (rank === 2) return 0.10;
    if (rank === 1) return 0.05;
    return 0;
  }

  function getWalletHeroRarityBonusLabel(heroLike) {
    const bonus = getWalletHeroRarityCombatBonus(heroLike);
    if (bonus <= 0) return '';
    const rarityName = String(heroLike?.rarityName || getDfKRarityName(heroLike?.rarity)).trim();
    return `${rarityName || 'Rarity'} bonus +${Math.round(bonus * 100)}% DMG/HP`;
  }

  function getWalletHeroActiveBonusLabel(heroLike) {
    if (!heroLike) return 'No NFT bonus active';
    if (isGen0WalletHero(heroLike)) return 'Active bonus: Gen0 +20% DMG, +10% SPEED, +10% LIFE, +30% HEALING';
    const rarityLabel = getWalletHeroRarityBonusLabel(heroLike);
    if (rarityLabel) return `Active bonus: ${rarityLabel}`;
    const rarityName = String(heroLike.rarityName || getDfKRarityName(heroLike.rarity) || 'Common').trim();
    return `Active bonus: ${rarityName} rarity, no stat bonus`;
  }

  function compareWalletHeroes(a, b) {
    const typeDelta = DFK_SLOT_ORDER.indexOf(a.type) - DFK_SLOT_ORDER.indexOf(b.type);
    if (typeDelta !== 0) return typeDelta;

    // Auto-select priority, within each class:
    // Gen0 highest rarity + level > Gen0 highest rarity > Gen0 highest level >
    // non-Gen0 highest rarity + level > non-Gen0 highest rarity > non-Gen0 highest level.
    const gen0Delta = (isGen0WalletHero(b) ? 1 : 0) - (isGen0WalletHero(a) ? 1 : 0);
    if (gen0Delta !== 0) return gen0Delta;
    const rarityDelta = getWalletHeroRarityRank(b) - getWalletHeroRarityRank(a);
    if (rarityDelta !== 0) return rarityDelta;
    const levelDelta = Number(b.level || 0) - Number(a.level || 0);
    if (levelDelta !== 0) return levelDelta;
    const chainDelta = String(a.chainKey || '').localeCompare(String(b.chainKey || ''));
    if (chainDelta !== 0) return chainDelta;
    return getWalletHeroNumericId(a) - getWalletHeroNumericId(b);
  }

  function getWalletHeroKey(heroLike) {
    return `${String(heroLike && (heroLike.chainKey || 'wallet'))}:${String(heroLike && (heroLike.id || heroLike.rawId || ''))}`;
  }

  function normalizeHeroMediaUrl(url) {
    const raw = String(url || '').trim();
    if (!raw) return '';
    if (raw.startsWith('ipfs://')) {
      const path = raw.slice('ipfs://'.length).replace(/^ipfs\//i, '');
      return `https://cloudflare-ipfs.com/ipfs/${path}`;
    }
    return raw;
  }

  function getWalletHeroFallbackSources(heroLike) {
    const heroType = heroLike && heroLike.type ? heroLike.type : '';
    const customPortraitUrl = heroLike && heroLike.customPortraitUrl ? String(heroLike.customPortraitUrl).trim() : '';
    return [
      customPortraitUrl,
      getTowerDefaultHeroImage(heroLike),
      getDefaultHeroImageForType(heroType),
    ].filter(Boolean);
  }

  const KNOWN_GEN0_HERO_IDS = new Set(['367', '1536']);
  const KNOWN_NON_GEN0_HERO_IDS = new Set(['236127', '1000000210744', '1000000394507', '1000000435777', '1000000580117']);

  function normalizeHeroIdText(heroId) {
    return String(heroId == null ? '' : heroId).trim().replace(/[^0-9]/g, '').replace(/^0+(?=\d)/, '');
  }

  function getUnpaddedHeroIdText(heroId) {
    const normalized = normalizeHeroIdText(heroId);
    if (!normalized) return '';
    try {
      const id = BigInt(normalized);
      const trillion = 1000000000000n;
      if (id >= 2000000000000n) return String(id - 2000000000000n);
      if (id >= trillion) return String(id - trillion);
    } catch (_error) {}
    return normalized;
  }

  function extractNumericTraitValue(rawValue) {
    if (rawValue == null) return null;
    const match = String(rawValue).match(/-?\d+/);
    if (!match) return null;
    const value = Number(match[0]);
    return Number.isFinite(value) && value >= 0 ? value : null;
  }

  function extractHeroMetadataGeneration(metadata) {
    if (!metadata || typeof metadata !== 'object') return null;
    const directKeys = ['generation', 'Generation', 'gen', 'Gen'];
    for (const key of directKeys) {
      if (metadata[key] == null) continue;
      const value = extractNumericTraitValue(metadata[key]);
      if (value != null) return value;
    }
    const attributes = Array.isArray(metadata.attributes) ? metadata.attributes : [];
    for (const attr of attributes) {
      if (!attr || typeof attr !== 'object') continue;
      const name = String(attr.trait_type || attr.traitType || attr.name || attr.key || '').trim().toLowerCase();
      if (!['generation', 'gen'].includes(name)) continue;
      const value = extractNumericTraitValue(attr.value ?? attr.display_value);
      if (value != null) return value;
    }
    return null;
  }

  async function readHeroMetadata(heroId) {
    const id = normalizeHeroIdText(heroId);
    if (!id) return null;
    try {
      const response = await fetch(`https://heroes.defikingdoms.com/token/${encodeURIComponent(id)}`, { cache: 'force-cache' });
      if (!response.ok) return null;
      return await response.json();
    } catch (_error) {
      return null;
    }
  }

  async function readHeroGenerationFromMetadata(heroId) {
    const candidates = Array.from(new Set([
      normalizeHeroIdText(heroId),
      getUnpaddedHeroIdText(heroId),
    ].filter(Boolean)));

    for (const candidate of candidates) {
      const metadata = await readHeroMetadata(candidate);
      const generation = extractHeroMetadataGeneration(metadata);
      if (generation != null) {
        return { generation, metadata, metadataHeroId: candidate };
      }
    }

    return { generation: null, metadata: null, metadataHeroId: candidates[0] || '' };
  }

  function getKnownHeroGen0Override(heroId) {
    const normalized = normalizeHeroIdText(heroId);
    const unpadded = getUnpaddedHeroIdText(heroId);
    if (KNOWN_NON_GEN0_HERO_IDS.has(normalized) || KNOWN_NON_GEN0_HERO_IDS.has(unpadded)) return false;
    if (KNOWN_GEN0_HERO_IDS.has(normalized) || KNOWN_GEN0_HERO_IDS.has(unpadded)) return true;
    return null;
  }

  function getFallbackGen0FromHeroId(heroId) {
    const override = getKnownHeroGen0Override(heroId);
    if (override != null) return override;
    const id = Number(getUnpaddedHeroIdText(heroId));
    return Number.isFinite(id) && id >= 1 && id <= 2000;
  }

  async function readHeroMetadataImage(tokenUri) {
    const raw = String(tokenUri || '').trim();
    if (!raw) return '';
    try {
      if (raw.startsWith('data:application/json;base64,')) {
        const decoded = JSON.parse(atob(raw.split(',')[1] || ''));
        return normalizeHeroMediaUrl(decoded.image || decoded.image_url || decoded.imageUrl || '');
      }
      if (raw.startsWith('data:application/json,')) {
        const decoded = JSON.parse(decodeURIComponent(raw.split(',').slice(1).join(',')));
        return normalizeHeroMediaUrl(decoded.image || decoded.image_url || decoded.imageUrl || '');
      }
      if (/^https?:\/\/heroes\.defikingdoms\.com\/token\//i.test(raw)) {
        return '';
      }
      if (/^https?:\/\//i.test(raw) && !/^https?:\/\/cloudflare-ipfs\.com\//i.test(raw)) {
        return '';
      }
      const response = await fetch(raw, { cache: 'force-cache' });
      if (!response.ok) return '';
      const json = await response.json();
      return normalizeHeroMediaUrl(json.image || json.image_url || json.imageUrl || '');
    } catch (error) {
      return '';
    }
  }

  function hasLoadedDfkNftsForDisplay() {
    const allHeroes = Array.isArray(game.allWalletHeroRoster) ? game.allWalletHeroRoster : [];
    const eligibleHeroes = Array.isArray(game.walletHeroRoster) ? game.walletHeroRoster : [];
    return allHeroes.some(hero => hero && hero.type) || eligibleHeroes.some(hero => hero && hero.type);
  }

  function shouldUsePlaceholderHeroImages() {
    if (!getConnectedWalletAddress()) return true;
    if (game.walletHeroLoadPending) return false;
    return !hasLoadedDfkNftsForDisplay();
  }

  function getPlaceholderHeroImageForType(type) {
    const key = String(type || '').trim().toLowerCase();
    return PLACEHOLDER_HERO_TILE_IMAGES[key] || '';
  }

  function getDefaultHeroImageForType(type) {
    const key = String(type || '').trim().toLowerCase();
    if (shouldUsePlaceholderHeroImages()) {
      const placeholder = getPlaceholderHeroImageForType(key);
      if (placeholder) return placeholder;
    }
    return HERO_TILE_IMAGES[key] || '';
  }

  function getSecondHeroImageForType(type) {
    const key = String(type || '').trim().toLowerCase();
    if (!key) return '';
    if (HERO_TILE_IMAGES[`${key}_alt`]) return HERO_TILE_IMAGES[`${key}_alt`];
    const base = HERO_TILE_IMAGES[key] || '';
    if (!base) return '';
    return base.replace(/(\.[a-z0-9]+)$/i, '2$1');
  }

  function isSecondHeroVisual(tower) {
    return !!(tower && Number(tower.heroVisualVariant || 1) === 2 && !tower.isSatellite && !tower.isSacrificeMonk);
  }

  function isSecondMonkVisual(tower) {
    return !!(tower && tower.type === 'monk' && Number(tower.heroVisualVariant || tower.monkVisualVariant || 1) === 2 && !tower.isSacrificeMonk);
  }

  function getTowerDefaultHeroImage(tower) {
    const type = tower && tower.type ? String(tower.type).trim().toLowerCase() : '';
    if (shouldUsePlaceholderHeroImages()) {
      const placeholder = getPlaceholderHeroImageForType(type);
      if (placeholder) return placeholder;
    }
    if (isSecondHeroVisual(tower)) return getSecondHeroImageForType(type) || getDefaultHeroImageForType(type);
    return getDefaultHeroImageForType(type);
  }

  function getMonk2HeroImage() {
    if (shouldUsePlaceholderHeroImages()) return getPlaceholderHeroImageForType('monk') || HERO_TILE_IMAGES.monk || '';
    return getSecondHeroImageForType('monk') || HERO_TILE_IMAGES.monk || '';
  }

  function getWalletHeroImage(hero) {
    const primary = normalizeHeroMediaUrl(hero && hero.imageUrl ? hero.imageUrl : '');
    if (primary) return primary;
    return getDefaultHeroImageForType(hero && hero.type ? hero.type : '') || '';
  }

  function getChampionPortraitImage(heroLike, championKey = '') {
    const explicitType = heroLike && heroLike.type ? String(heroLike.type).trim().toLowerCase() : '';
    const explicitChampionType = heroLike && heroLike.towerType ? String(heroLike.towerType).trim().toLowerCase() : '';
    return getDefaultHeroImageForType(explicitChampionType)
      || getDefaultHeroImageForType(championKey ? `champion_${championKey}` : '')
      || getDefaultHeroImageForType(championKey)
      || getDefaultHeroImageForType(explicitType)
      || getWalletHeroImage(heroLike)
      || '';
  }

  function getDfKClassName(classId) {
    const id = Number(classId);
    return DFK_CLASS_NAMES[id] || `Class ${Number.isFinite(id) ? id : '--'}`;
  }

  function getDfKRarityName(rarity) {
    const id = Number(rarity);
    return DFK_RARITY_NAMES[id] || 'Unknown';
  }

  function getDfKRarityClassName(rarity) {
    const id = Number(rarity);
    return DFK_RARITY_CLASS_NAMES[id] || 'unknown';
  }

  function getDfKRarityShortName(rarity) {
    const id = Number(rarity);
    return DFK_RARITY_SHORT_NAMES[id] || 'NFT';
  }

  function getWalletHeroRarityParts(heroLike) {
    if (!heroLike || isGen0WalletHero(heroLike)) return [];
    const rarityName = String(heroLike.rarityName || getDfKRarityName(heroLike.rarity)).trim();
    return rarityName && rarityName !== 'Unknown' ? [rarityName] : [];
  }

  function getTowerWalletHeroRarity(tower) {
    if (!tower || !tower.walletHeroId || isGen0BonusTower(tower) || tower.walletHeroIsGen0 === true) return null;
    const rarity = Number(tower.walletHeroRarity);
    const name = String(tower.walletHeroRarityName || getDfKRarityName(rarity)).trim();
    if (!Number.isFinite(rarity) || !name || name === 'Unknown') return null;
    return { rarity, name, className: getDfKRarityClassName(rarity), shortName: getDfKRarityShortName(rarity) };
  }

  function getTransferHeroSearchValue() {
    return String(game.transferHeroSearch || '').trim().toLowerCase();
  }

  function getTransferHeroSortValue() {
    return String(game.transferHeroSort || 'level_desc').trim().toLowerCase();
  }

  function compareTransferHeroes(a, b) {
    const aClass = String((a && a.className) || '').toLowerCase();
    const bClass = String((b && b.className) || '').toLowerCase();
    const aLevel = Number((a && a.level) || 0);
    const bLevel = Number((b && b.level) || 0);
    const aId = Number((a && a.id) || 0);
    const bId = Number((b && b.id) || 0);
    switch (getTransferHeroSortValue()) {
      case 'class_asc':
        return aClass.localeCompare(bClass) || bLevel - aLevel || aId - bId;
      case 'class_level':
        return aClass.localeCompare(bClass) || bLevel - aLevel || aId - bId;
      case 'level_asc':
        return aLevel - bLevel || aClass.localeCompare(bClass) || aId - bId;
      case 'level_desc':
      default:
        return bLevel - aLevel || aClass.localeCompare(bClass) || aId - bId;
    }
  }

  function getFilteredTransferHeroes() {
    const list = Array.isArray(game.allWalletHeroRoster) ? game.allWalletHeroRoster.filter((hero) => hero && hero.transferSupported !== false).slice() : [];
    const query = getTransferHeroSearchValue();
    const filtered = !query ? list : list.filter((hero) => {
      const haystack = [hero.id, hero.className, hero.subClassName, hero.rarityName, `level ${hero.level}`, `lvl ${hero.level}`].join(' ').toLowerCase();
      return haystack.includes(query);
    });
    return filtered.sort(compareTransferHeroes);
  }

  function getTransferHeroPageCount(filteredHeroes = null) {
    const heroes = Array.isArray(filteredHeroes) ? filteredHeroes : getFilteredTransferHeroes();
    const pageSize = Math.max(1, Number(game.transferHeroesPageSize || 24));
    return Math.max(1, Math.ceil(heroes.length / pageSize));
  }

  function clampTransferHeroPage(filteredHeroes = null) {
    const pageCount = getTransferHeroPageCount(filteredHeroes);
    game.transferHeroesPage = Math.min(pageCount, Math.max(1, Number(game.transferHeroesPage || 1)));
    return game.transferHeroesPage;
  }

  function getPaginatedTransferHeroes(filteredHeroes = null) {
    const heroes = Array.isArray(filteredHeroes) ? filteredHeroes : getFilteredTransferHeroes();
    const pageSize = Math.max(1, Number(game.transferHeroesPageSize || 24));
    const page = clampTransferHeroPage(heroes);
    const start = (page - 1) * pageSize;
    return heroes.slice(start, start + pageSize);
  }

  function getSelectedTransferHeroIds() {
    const selected = game.transferHeroSelection || {};
    return Object.keys(selected).filter((id) => selected[id]);
  }

  function syncTransferHeroSummary() {
    if (!els.transferHeroesSummary) return;
    const count = getSelectedTransferHeroIds().length;
    els.transferHeroesSummary.textContent = count ? `${count} hero${count === 1 ? '' : 'es'} selected.` : 'No heroes selected.';
  }

  function setTransferHeroesStatus(message) {
    if (els.transferHeroesStatus) els.transferHeroesStatus.textContent = message;
  }

  function clearTransferHeroSelection() {
    game.transferHeroSelection = {};
    syncTransferHeroSummary();
  }

  function toggleTransferHeroSelection(heroId) {
    const id = String(heroId || '').trim();
    if (!id || game.transferHeroesBusy) return;
    if (!game.transferHeroSelection || typeof game.transferHeroSelection !== 'object') game.transferHeroSelection = {};
    game.transferHeroSelection[id] = !game.transferHeroSelection[id];
    if (!game.transferHeroSelection[id]) delete game.transferHeroSelection[id];
    renderTransferHeroesModal();
  }

  function renderTransferHeroesModal() {
    if (!els.transferHeroesBody) return;
    const address = getConnectedWalletAddress();
    const allHeroes = Array.isArray(game.allWalletHeroRoster) ? game.allWalletHeroRoster : [];
    const filteredHeroes = getFilteredTransferHeroes();
    const heroes = getPaginatedTransferHeroes(filteredHeroes);
    const pageCount = getTransferHeroPageCount(filteredHeroes);
    const currentPage = clampTransferHeroPage(filteredHeroes);
    if (els.transferHeroesRecipient && els.transferHeroesRecipient.value !== String(game.transferHeroRecipient || '')) els.transferHeroesRecipient.value = String(game.transferHeroRecipient || '');
    if (els.transferHeroesSearch && els.transferHeroesSearch.value !== String(game.transferHeroSearch || '')) els.transferHeroesSearch.value = String(game.transferHeroSearch || '');
    if (els.transferHeroesSort && els.transferHeroesSort.value !== String(game.transferHeroSort || 'level_desc')) els.transferHeroesSort.value = String(game.transferHeroSort || 'level_desc');
    syncTransferHeroSummary();
    if (!address) {
      setTransferHeroesStatus('Connect a wallet to load NFTs. Transfers still use DFK Chain only.');
      els.transferHeroesBody.innerHTML = '<div class="transfer-heroes-empty">Wallet not connected.</div>';
      if (els.confirmTransferHeroesBtn) els.confirmTransferHeroesBtn.disabled = true;
      if (els.transferHeroesPageLabel) els.transferHeroesPageLabel.textContent = 'Page 1 / 1';
      if (els.transferHeroesPrevBtn) els.transferHeroesPrevBtn.disabled = true;
      if (els.transferHeroesNextBtn) els.transferHeroesNextBtn.disabled = true;
      return;
    }
    if (game.walletHeroLoadPending) setTransferHeroesStatus('Searching for NFTs...');
    else if (!allHeroes.length) setTransferHeroesStatus('No transferable DFK Chain NFTs are currently loaded for this wallet.');
    else if (!game.transferHeroesBusy) setTransferHeroesStatus(`Loaded ${allHeroes.length} transferable DFK Chain NFT${allHeroes.length === 1 ? '' : 's'} from your wallet. Metis heroes are available in the NFT bonus picker.`);
    if (!filteredHeroes.length) {
      els.transferHeroesBody.innerHTML = '<div class="transfer-heroes-empty">No heroes match this search.</div>';
    } else {
      els.transferHeroesBody.innerHTML = heroes.map((hero) => {
        const selected = !!(game.transferHeroSelection && game.transferHeroSelection[String(hero.id)]);
        const imageSrc = getWalletHeroImage(hero);
        return `<button class="transfer-hero-card${selected ? ' is-selected' : ''}" type="button" data-transfer-hero-id="${escapeHtml(String(hero.id))}">
          <span class="transfer-hero-card-art-wrap">
            <img src="${escapeHtml(imageSrc)}" alt="Hero ${escapeHtml(String(hero.id))}" loading="lazy" />
          </span>
          <span class="transfer-hero-card-meta">
            <span class="transfer-hero-card-topline">
              <span class="transfer-hero-card-title">Hero #${escapeHtml(String(hero.id))}</span>
              <span class="transfer-hero-card-badge">${selected ? 'Selected' : 'Select'}</span>
            </span>
            <span class="transfer-hero-card-sub">${escapeHtml(hero.className)} • ${escapeHtml(hero.subClassName || '—')}</span>
            <span class="transfer-hero-card-sub">${escapeHtml(hero.rarityName)} • Level ${escapeHtml(String(hero.level))}</span>
            <span class="transfer-hero-card-sub">${escapeHtml(getWalletHeroSourceBadge(hero))}</span>
          </span>
        </button>`;
      }).join('');
      Array.from(els.transferHeroesBody.querySelectorAll('[data-transfer-hero-id]')).forEach((button) => {
        const heroId = button.getAttribute('data-transfer-hero-id') || '';
        const hero = allHeroes.find((entry) => String(entry.id) === String(heroId));
        const img = button.querySelector('img');
        if (img && hero) img.addEventListener('error', () => handleWalletHeroImageError(img, hero), { once: false });
        button.addEventListener('click', () => toggleTransferHeroSelection(heroId));
      });
    }
    const selectedIds = getSelectedTransferHeroIds();
    const hasSelection = selectedIds.length > 0;
    const recipient = String(game.transferHeroRecipient || '').trim();
    if (els.confirmTransferHeroesBtn) {
      els.confirmTransferHeroesBtn.disabled = !hasSelection || !recipient || game.transferHeroesBusy;
      els.confirmTransferHeroesBtn.textContent = game.transferHeroesBusy ? 'Sending…' : `Send selected hero${selectedIds.length === 1 ? '' : 'es'}`;
    }
    if (els.transferHeroesSelectAllBtn) els.transferHeroesSelectAllBtn.disabled = !heroes.length || game.transferHeroesBusy;
    if (els.transferHeroesClearBtn) els.transferHeroesClearBtn.disabled = !hasSelection || game.transferHeroesBusy;
    if (els.transferHeroesPageLabel) els.transferHeroesPageLabel.textContent = `Page ${currentPage} / ${pageCount}`;
    if (els.transferHeroesPrevBtn) els.transferHeroesPrevBtn.disabled = currentPage <= 1 || game.transferHeroesBusy || !filteredHeroes.length;
    if (els.transferHeroesNextBtn) els.transferHeroesNextBtn.disabled = currentPage >= pageCount || game.transferHeroesBusy || !filteredHeroes.length;
  }

  function closeTransferHeroesModal() {
    if (!els.transferHeroesModal) return;
    els.transferHeroesModal.classList.add('hidden');
    els.transferHeroesModal.setAttribute('aria-hidden', 'true');
  }

  function openTransferHeroesModal() {
    closeIntroModal();
    closeBountyModal();
    closeQuestsModal();
    closeTrackedRunsModal();
    closeKnownRelicsModal();
    closeContinueOfferModal();
    if (els.transferHeroesModal) {
      els.transferHeroesModal.classList.remove('hidden');
      els.transferHeroesModal.setAttribute('aria-hidden', 'false');
    }
    if (getConnectedWalletAddress() && (!Array.isArray(game.allWalletHeroRoster) || !game.allWalletHeroRoster.length) && !game.walletHeroLoadPending && !game.walletHeroAutoLoadedKey) {
      loadWalletHeroes(false).catch((error) => console.error(error));
    }
    clampTransferHeroPage();
    renderTransferHeroesModal();
  }

  function selectAllVisibleTransferHeroes() {
    const visible = getPaginatedTransferHeroes();
    if (!visible.length || game.transferHeroesBusy) return;
    if (!game.transferHeroSelection || typeof game.transferHeroSelection !== 'object') game.transferHeroSelection = {};
    visible.forEach((hero) => { game.transferHeroSelection[String(hero.id)] = true; });
    renderTransferHeroesModal();
  }

  async function confirmTransferHeroes() {
    if (game.transferHeroesBusy) return;
    const heroIds = getSelectedTransferHeroIds();
    const recipient = String(game.transferHeroRecipient || '').trim();
    if (!heroIds.length) { showBanner('Select at least one hero first.', 1700); return; }
    if (!window.DFKDefenseWallet || typeof window.DFKDefenseWallet.transferHeroes !== 'function') { showBanner('Wallet transfer tool unavailable.', 1700); return; }
    game.transferHeroesBusy = true;
    renderTransferHeroesModal();
    try {
      setTransferHeroesStatus(`Preparing ${heroIds.length} hero transfer${heroIds.length === 1 ? '' : 's'}…`);
      await window.DFKDefenseWallet.transferHeroes(heroIds, recipient, {
        onProgress: ({ stage, tokenId, index, total }) => {
          if (stage === 'confirm') setTransferHeroesStatus(`Confirm hero ${tokenId} (${index + 1}/${total}) in your wallet…`);
          else if (stage === 'pending') setTransferHeroesStatus(`Waiting for hero ${tokenId} on chain (${index + 1}/${total})…`);
          else if (stage === 'confirmed') setTransferHeroesStatus(`Transferred hero ${tokenId} (${index + 1}/${total}).`);
        }
      });
      showBanner(`Transferred ${heroIds.length} hero${heroIds.length === 1 ? '' : 'es'}.`, 2200);
      clearTransferHeroSelection();
      await loadWalletHeroes(true).catch(() => null);
      renderWalletHeroBonusPanel();
      renderHirePanel();
      renderTransferHeroesModal();
    } catch (error) {
      console.error('Hero transfer failed', error);
      setTransferHeroesStatus(error && error.message ? error.message : 'Hero transfer failed.');
      showBanner(error && error.message ? error.message : 'Hero transfer failed.', 2200);
    } finally {
      game.transferHeroesBusy = false;
      renderTransferHeroesModal();
    }
  }

  function handleWalletHeroImageError(imgEl, heroLike) {
    if (!imgEl) return;
    const fallback = getDefaultHeroImageForType(heroLike && heroLike.type ? heroLike.type : '');
    if (fallback && imgEl.getAttribute('src') !== fallback) {
      imgEl.src = fallback;
      return;
    }
    imgEl.classList.add('wallet-hero-image-fallback');
  }

  function toggleWalletHeroType(type) {
    if (!type) return;
    if (!game.walletHeroExpandedTypes || typeof game.walletHeroExpandedTypes !== 'object') game.walletHeroExpandedTypes = {};
    game.walletHeroExpandedTypes[type] = !game.walletHeroExpandedTypes[type];
    renderWalletHeroBonusPanel();
  }

  function setWalletHeroSearch(type, value) {
    if (!type) return;
    if (!game.walletHeroSearch || typeof game.walletHeroSearch !== 'object') game.walletHeroSearch = {};
    game.walletHeroSearch[type] = String(value || '').trim();
    renderWalletHeroBonusPanel();
  }

  let walletHeroSectionHome = null;
  let walletHeroSectionMarker = null;

  function ensureWalletHeroSectionHome() {
    if (!els.walletHeroBonusSection) return;
    if (!walletHeroSectionHome) walletHeroSectionHome = els.walletHeroBonusSection.parentNode;
    if (!walletHeroSectionMarker && walletHeroSectionHome) {
      walletHeroSectionMarker = document.createComment('wallet-hero-modal-home');
      walletHeroSectionHome.insertBefore(walletHeroSectionMarker, els.walletHeroBonusSection.nextSibling);
    }
  }

  function moveWalletHeroSectionToModalLayer() {
    if (!els.walletHeroBonusSection || !document.body) return;
    ensureWalletHeroSectionHome();
    if (els.walletHeroBonusSection.parentNode !== document.body) document.body.appendChild(els.walletHeroBonusSection);
  }

  function restoreWalletHeroSectionHome() {
    if (!els.walletHeroBonusSection) return;
    ensureWalletHeroSectionHome();
    if (walletHeroSectionHome && walletHeroSectionMarker && walletHeroSectionMarker.parentNode === walletHeroSectionHome && els.walletHeroBonusSection.parentNode !== walletHeroSectionHome) {
      walletHeroSectionHome.insertBefore(els.walletHeroBonusSection, walletHeroSectionMarker);
    }
  }

  function setWalletHeroPanelCollapsed(collapsed) {
    game.walletHeroPanelCollapsed = !!collapsed;
    const isOpen = !collapsed;
    if (isOpen) moveWalletHeroSectionToModalLayer();
    if (els.walletHeroBonusSection) els.walletHeroBonusSection.classList.toggle('collapsed', !!collapsed);
    if (els.walletHeroBonusSection) els.walletHeroBonusSection.classList.toggle('modal-open', isOpen);
    if (els.walletHeroBonusToggle) els.walletHeroBonusToggle.setAttribute('aria-expanded', collapsed ? 'false' : 'true');
    if (els.walletHeroBonusPanelBody) els.walletHeroBonusPanelBody.setAttribute('aria-modal', isOpen ? 'true' : 'false');
    document.body.classList.toggle('wallet-heroes-modal-open', isOpen);
    if (!isOpen) restoreWalletHeroSectionHome();
    if (els.walletHeroBonusSummary) {
      const rosterCount = Array.isArray(game.walletHeroRoster) ? game.walletHeroRoster.length : 0;
      const allLoadedCount = Array.isArray(game.allWalletHeroRoster) ? game.allWalletHeroRoster.filter(hero => hero && hero.type).length : rosterCount;
      const axieCount = Array.isArray(game.walletAxieRoster) ? game.walletAxieRoster.length : 0;
      const selectedCount = Object.keys(game.selectedWalletHeroes || {}).length;
      els.walletHeroBonusSummary.textContent = game.walletHeroLoadPending
        ? 'Searching for heroes and champions…'
        : `${selectedCount} selected • ${allLoadedCount || rosterCount} loaded`;
    }
    if (els.walletHeroBonusSummary && !game.walletHeroLoadPending) {
      const rosterCount = Array.isArray(game.walletHeroRoster) ? game.walletHeroRoster.length : 0;
      const allLoadedCount = Array.isArray(game.allWalletHeroRoster) ? game.allWalletHeroRoster.filter(hero => hero && hero.type).length : rosterCount;
      const axieCount = Array.isArray(game.walletAxieRoster) ? game.walletAxieRoster.length : 0;
      const selectedCount = Object.keys(game.selectedWalletHeroes || {}).length;
      els.walletHeroBonusSummary.textContent = `${selectedCount} selected â€¢ ${allLoadedCount || rosterCount} heroes${axieCount ? ` â€¢ ${axieCount} Axie pets` : ''} loaded`;
    }
  }


  function getSelectedWalletHero(type) {
    const selectedId = game.selectedWalletHeroes ? game.selectedWalletHeroes[type] : null;
    if (!selectedId) return null;
    return (game.walletHeroRoster || []).find(hero => hero.type === type && String(hero.id) === String(selectedId)) || null;
  }

  function isStartingWalletHeroPlacementWindow() {
    if (game.phase === SETUP_PHASES.GAME_OVER || game.runningWave) return false;
    if (Number(game.waveNumber || 0) === 0 && Number(game.activeWaveBase || 0) === 0) return true;
    return isAwaitingManualStartAfterWaveJump();
  }

  function getSelectedWalletHeroForHire(type, usesBonus = false) {
    if (usesBonus) return null;
    const selectedWalletHero = getSelectedWalletHero(type);
    if (!selectedWalletHero) return null;
    if (type === 'warrior' && canUseWarriorNftReplacement()) return selectedWalletHero;
    if (isGen0WalletHero(selectedWalletHero) && !isStartingWalletHeroPlacementWindow()) return null;
    return selectedWalletHero;
  }

  function hasSelectedWarriorWalletHero() {
    return !!getSelectedWalletHero('warrior');
  }

  function getActiveNonSatelliteWarrior() {
    return (game.towers || []).find((tower) => tower && tower.hp > 0 && tower.type === 'warrior' && !tower.isSatellite && !tower.isChampion) || null;
  }

  function hasWarriorPlacedThisRun() {
    if (game.warriorPlacedThisRun) return true;
    if (getActiveNonSatelliteWarrior()) return true;
    return false;
  }

  function requiresWarriorBeforeHeroPlacement(type) {
    if (!type || type === 'warrior') return false;
    if (String(type).startsWith('champion_')) return !hasWarriorPlacedThisRun();
    return !hasWarriorPlacedThisRun();
  }

  function canUseWarriorNftReplacement() {
    if (game.phase === SETUP_PHASES.GAME_OVER) return false;
    if (!hasSelectedWarriorWalletHero()) return false;
    if (getActiveNonSatelliteWarrior()) return false;
    if (game.placingHeroType === 'warrior' && !game.placingSatelliteSourceId) return false;
    if (game.pendingMilestoneHeroPlacement && game.pendingMilestoneHeroPlacement.heroType === 'warrior') return false;
    return Number(game.waveNumber || 0) > 0 || game.runningWave || Number(game.activeWaveBase || 0) > 0 || !!game.warriorNftReplacementHeroId;
  }

  function rememberWarriorNftForReplacement(tower) {
    if (!tower || tower.type !== 'warrior' || tower.isSatellite || tower.isChampion || !tower.walletHeroId) return;
    game.warriorNftReplacementHeroId = String(tower.walletHeroId);
    game.warriorNftReplacementWasGen0 = !!tower.walletHeroIsGen0;
    if (!game.selectedWalletHeroes || typeof game.selectedWalletHeroes !== 'object') game.selectedWalletHeroes = {};
    const currentSelected = getSelectedWalletHero('warrior');
    if (!currentSelected || String(currentSelected.id) !== String(tower.walletHeroId)) {
      game.selectedWalletHeroes.warrior = String(tower.walletHeroId);
    }
  }

  function clearUnplacedStartingGen0Placement() {
    if (!game.placingWalletHeroId) return;
    const selected = (game.walletHeroRoster || []).find(hero => String(hero.id) === String(game.placingWalletHeroId));
    if (!selected || !isGen0WalletHero(selected)) return;
    if (isStartingWalletHeroPlacementWindow()) return;
    game.placingHeroType = null;
    game.placingHeroCost = 0;
    game.placingHeroUsesBonus = false;
    game.placingSatelliteSourceId = null;
    game.placingWalletHeroId = null;
  }

  function getChampionWavesWaited() {
    const progressedWave = Math.max(0, Number(game.waveNumber || 0), Number(game.activeWaveBase || 0));
    const anchor = Math.max(0, Number(game.championWaitAnchorWave || 0));
    // The anchor is the start of the current rest period. Do not clear it just
    // because the champion is off-field; after each deployment the anchor is
    // intentionally reset when the champion leaves, so the next deployment must
    // rest a fresh 20 waves. Extra waves banked before a deployment must not
    // carry into the next rest period.
    if (anchor > progressedWave) return 0;
    return Math.max(0, progressedWave - anchor);
  }

  function getChampionTestRoster() {
    if (!canUseChampionWaveOneOverride()) return [];
    return [{
      key: 'dreadknight',
      hero: {
        id: 'ADMIN-CHAMPION-DK',
        level: 30,
        chainName: 'Authorized',
        className: 'DreadKnight',
      },
      definition: CHAMPION_DEFINITIONS.dreadknight,
    }];
  }

  function getSelectedChampionRecord() {
    const roster = Array.isArray(game.championRoster) ? game.championRoster : [];
    const selectedHeroId = String(game.selectedChampionHeroId || '');
    const snapshot = game.selectedChampionConfirmed && game.selectedChampionSnapshot && game.selectedChampionSnapshot.key === game.selectedChampionKey
      ? game.selectedChampionSnapshot
      : null;
    const exact = roster.find((entry) => entry && entry.key === game.selectedChampionKey && String(entry.hero.id) === selectedHeroId);
    if (exact) {
      if (snapshot && String(snapshot.hero?.id || '') === String(exact.hero?.id || '') && Number(snapshot.hero?.level || 1) > Number(exact.hero?.level || 1)) {
        return { ...exact, hero: { ...exact.hero, ...snapshot.hero, level: Number(snapshot.hero.level || exact.hero.level || 1) } };
      }
      return exact;
    }
    const byKey = roster.find((entry) => entry && entry.key === game.selectedChampionKey);
    if (byKey) {
      if (game.selectedChampionConfirmed && (!selectedHeroId || String(byKey.hero.id) !== selectedHeroId)) {
        game.selectedChampionHeroId = String(byKey.hero.id);
        game.selectedChampionSnapshot = { key: byKey.key, hero: { ...byKey.hero }, definition: byKey.definition };
      }
      if (snapshot && String(snapshot.hero?.id || '') === String(byKey.hero?.id || '') && Number(snapshot.hero?.level || 1) > Number(byKey.hero?.level || 1)) {
        return { ...byKey, hero: { ...byKey.hero, ...snapshot.hero, level: Number(snapshot.hero.level || byKey.hero.level || 1) } };
      }
      return byKey;
    }
    if (snapshot) {
      return snapshot;
    }
    return null;
  }

  function isCasterTowerType(type) {
    return ['wizard', 'seer', 'priest', 'champion_sage', 'champion_spellbow'].includes(String(type || ''));
  }

  function hasLivingChampionOfType(type, excludeTowerId = null) {
    return game.towers.some((tower) => tower && tower.hp > 0 && tower.type === type && tower.id !== excludeTowerId);
  }

  function hasSageChampionBuff(tower) {
    return !!(tower && isCasterTowerType(tower.type) && hasLivingChampionOfType('champion_sage', tower.id));
  }

  function isMeleeHeroType(type) {
    return ['warrior', 'archer', 'pirate', 'monk', 'berserker', 'champion_dreadknight', 'champion_dragoon'].includes(String(type || ''));
  }

  function hasSageChampionMeleeBuff(tower) {
    return !!(tower && isMeleeHeroType(tower.type) && hasLivingChampionOfType('champion_sage', tower.id));
  }

  function isUnderSageGlowProtection(tower) {
    if (!tower || isStatueTower(tower) || Number(tower.hp || 0) <= 0) return false;
    return hasSageChampionBuff(tower) || hasSageChampionMeleeBuff(tower);
  }

  function getSageGlowProtectedAllies(sourceTower = null) {
    return (game.towers || []).filter((ally) => {
      if (!ally || Number(ally.hp || 0) <= 0) return false;
      if (sourceTower && ally.id === sourceTower.id) return false;
      return isUnderSageGlowProtection(ally);
    });
  }

  function hasDragoonLeadershipBuff(tower) {
    return !!(tower && !isStatueTower(tower) && hasLivingChampionOfType('champion_dragoon'));
  }

  function hasDragoonOverpowerBuff(tower) {
    return !!(tower && tower.buffs && tower.buffs.championOverpowerAura && tower.buffs.championOverpowerAura.until > now());
  }

  function getChampionPointTarget(sourceTower = null) {
    const enemies = getPortalPriorityEnemies(Math.max(1, game.enemies.length || 1));
    const inRange = sourceTower
      ? enemies.filter((enemy) => enemy && enemy.hp > 0 && dist(sourceTower, enemy) <= 4)
      : enemies;
    const preferred = inRange.filter((enemy) => enemy && enemy.hp > 0 && (enemy.isBoss || enemy.typeClass !== 'runner'));
    return preferred[0] || inRange[0] || null;
  }

  function knockbackEnemyTowardPortal(enemy, tiles = 1) {
    if (!enemy || !Number.isFinite(Number(tiles)) || Number(tiles) <= 0) return false;
    const current = now();
    const knockbackTiles = Math.max(1, Math.round(Number(tiles) || 1));
    let moved = false;
    for (let i = 0; i < knockbackTiles; i += 1) {
      const currentDistance = getPortalFlowDistance(enemy.x, enemy.y);
      const step = adjacentTiles(enemy.x, enemy.y)
        .filter((candidate) => canEnemyEnterIgnoringCrowd(candidate.x, candidate.y, enemy))
        .map((candidate) => ({
          ...candidate,
          distance: getPortalFlowDistance(candidate.x, candidate.y),
          crowdPenalty: getEnemyOccupancy(candidate.x, candidate.y, enemy?.id || null, getEnemyOccupancyClass(enemy)) * 0.08,
        }))
        .filter((candidate) => Number.isFinite(candidate.distance) && candidate.distance < currentDistance)
        .sort((a, b) => (a.distance + a.crowdPenalty) - (b.distance + b.crowdPenalty))[0] || null;
      if (!step) break;
      updateEnemyFacingX(enemy, step.x);
      enemy.prevX = enemy.x;
      enemy.prevY = enemy.y;
      enemy.x = step.x;
      enemy.y = step.y;
      enemy.moveStartedAt = current;
      enemy.moveEndAt = current + Math.max(100, Math.round(getEnemyMoveMs(enemy) * 0.65));
      enemy.attacking = false;
      enemy.targetPath = [];
      enemy.stuckAt = 0;
      enemy.lastProgressAt = current;
      moved = true;
    }
    if (moved) {
      enemy.nextMoveAt = Math.max(enemy.nextMoveAt || 0, current + 500 + (knockbackTiles * 80));
      enemy.nextAttackAt = Math.max(enemy.nextAttackAt || 0, current + 350 + (knockbackTiles * 50));
      enemy.forcePortalUntil = Math.max(enemy.forcePortalUntil || 0, current + 900);
    }
    return moved;
  }

  function toTitleCaseWords(text) {
    return String(text || '').replace(/\w\S*/g, (word) => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase());
  }

  function formatChampionSkillMarkup(skillText) {
    const text = String(skillText || '').trim();
    if (!text) return '';
    const parts = text.split(/\s+[—-]\s+/);
    const skillName = toTitleCaseWords(parts.shift() || '');
    const detail = parts.join(' — ');
    const safeName = escapeHtml(skillName);
    const safeDetail = escapeHtml(detail);
    return safeDetail ? `<strong>${safeName}</strong> — ${safeDetail}` : `<strong>${safeName}</strong>`;
  }

  function ensureChampionCollapsedPreview() {
    if (!els.championPanel) return null;
    let preview = document.getElementById('championCollapsedPreview');
    if (!preview) {
      preview = document.createElement('div');
      preview.id = 'championCollapsedPreview';
      preview.className = 'champion-collapsed-preview hidden';
      els.championPanel.appendChild(preview);
    }
    return preview;
  }


  function getChampionDeployPreview(waited) {
    const safeWaited = Math.max(0, Number(waited || 0));
    const required = getChampionRequiredWaitWaves();
    if (safeWaited >= required) {
      const duration = safeWaited >= 40 ? 24 : 12;
      return { ready: true, text: `Ready to deploy • lasts ${duration} waves`, duration };
    }
    const remaining = Math.max(0, required - safeWaited);
    return { ready: false, text: `${remaining} wave${remaining === 1 ? '' : 's'} until deploy`, duration: 0 };
  }

  function maybeRemindChampionDeployment(options = {}) {
    const selected = getSelectedChampionRecord();
    if (!selected || !game.selectedChampionConfirmed) return false;
    const deployed = !!(game.championDeployedTowerId && game.towers.some((tower) => tower.id === game.championDeployedTowerId));
    if (deployed || (game.placingHeroType && String(game.placingHeroType).startsWith('champion_'))) return false;
    const waited = Math.max(0, Number(options.waited ?? getChampionWavesWaited()));
    if (waited < 30 || waited % 10 !== 0) return false;
    if (Number(game.championLastReminderWaited || 0) === waited) return false;
    const placement = getChampionDeployPreview(waited);
    if (!placement.ready) return false;
    game.championLastReminderWaited = waited;
    const message = `${selected.definition.label} is ready to deploy. Champions are worth checking every 10 waited waves starting at 30. Deploy now for ${placement.duration} waves.`;
    log(message);
    showBanner(message, 3200);
    return true;
  }

  function maybeOpenChampionModalAfterFifthHero(placedTower) {
    if (!placedTower || placedTower.isSatellite || placedTower.isChampion) return false;
    if (!Array.isArray(game.championRoster) || !game.championRoster.length) return false;
    if (game.selectedChampionConfirmed || game.runningWave || !(Number(game.waveNumber || 0) === 0 || isAwaitingManualStartAfterWaveJump())) return false;
    if (!game.portal || game.playerObstacleCount < getTargetPlayerObstacleCount()) return false;
    if (!(game.phase === SETUP_PHASES.BATTLE || isAwaitingManualStartAfterWaveJump())) return false;
    const normalHeroCount = (game.towers || []).filter((tower) => tower && !tower.isSatellite && !tower.isChampion && Number(tower.hp || 0) > 0).length;
    if (normalHeroCount !== 5) return false;
    game.championModalForceChoice = true;
    window.setTimeout(() => {
      try { showChampionInfoModal(); } catch (_error) {}
    }, 0);
    return true;
  }


  function renderChampionCollapsedPreview() {
    const preview = ensureChampionCollapsedPreview();
    if (!preview) return;
    const selected = getSelectedChampionRecord();
    const shouldShow = !!(game.championPanelCollapsed && selected);
    preview.classList.toggle('hidden', !shouldShow);
    preview.setAttribute('aria-hidden', shouldShow ? 'false' : 'true');
    if (!shouldShow) {
      preview.innerHTML = '';
      return;
    }
    const hero = selected.hero || {};
    const definition = selected.definition || {};
    const waited = getChampionWavesWaited();
    const deployed = !!(game.championDeployedTowerId && game.towers.some((tower) => tower.id === game.championDeployedTowerId));
    const placement = getChampionDeployPreview(waited);
    const quickDeployAvailable = !!selected && !deployed && (game.selectedChampionConfirmed || Number(game.waveNumber || 0) > 0);
    const quickButton = quickDeployAvailable
      ? `<button id="championQuickDeployBtn" type="button" class="wallet-btn secondary champion-quick-deploy-btn"${!game.placingHeroType ? '' : ' disabled'}>Deploy</button>`
      : '';
    preview.innerHTML = `<div class="champion-collapsed-preview-card"><img class="champion-collapsed-preview-portrait" src="${getChampionPortraitImage(hero, definition.key || '')}" alt="${escapeHtml(definition.label || 'Champion')}"><div class="champion-collapsed-preview-meta"><div class="champion-collapsed-preview-class">${escapeHtml(definition.label || 'Champion')}</div><div class="champion-collapsed-preview-line">Lvl ${escapeHtml(String(hero.level || 1))} • ${escapeHtml(placement.text)}</div>${quickButton}</div></div>`;
    const quickDeployBtn = document.getElementById('championQuickDeployBtn');
    if (quickDeployBtn) {
      quickDeployBtn.addEventListener('click', (event) => {
        event.preventDefault();
        event.stopPropagation();
        beginChampionPlacement({ allowEarly: !!game.championEarlyDeployPending });
      });
    }
  }

  function setChampionPanelCollapsed(collapsed) {
    game.championPanelCollapsed = !!collapsed;
    if (els.championPanel) els.championPanel.classList.toggle('collapsed', !!collapsed);
    if (els.championPanelToggle) els.championPanelToggle.setAttribute('aria-expanded', collapsed ? 'false' : 'true');
    if (els.championPanelSummary) {
      const selected = getSelectedChampionRecord();
      const waited = getChampionWavesWaited();
      const deployed = !!(game.championDeployedTowerId && game.towers.some((tower) => tower.id === game.championDeployedTowerId));
      const placement = getChampionDeployPreview(waited);
      els.championPanelSummary.textContent = game.walletHeroLoadPending
        ? 'Searching for heroes and champions…'
        : (collapsed
            ? (selected
                ? `${selected.definition.label}${deployed ? ` • Live thru ${game.championActiveUntilWave}` : (placement.ready ? ' • Ready' : '')}`
                : ((game.championRoster || []).length ? `${game.championRoster.length} detected` : 'None detected'))
            : (selected ? `${selected.definition.label} selected` : 'Choose after setup'));
    }
    renderChampionCollapsedPreview();
  }

  function getDetectedChampionRoster() {
    const bestByChampionKey = new Map();
    for (const hero of (game.allWalletHeroRoster || [])) {
      const primaryClass = String(hero.className || '').trim().toLowerCase().replace(/\s+/g, '');
      const key = CHAMPION_CLASS_LOOKUP[primaryClass] || '';
      if (!key) continue;
      const level = Math.max(1, Number(hero.level || 1));
      const existing = bestByChampionKey.get(key);
      const existingLevel = existing ? Math.max(1, Number(existing.hero.level || 1)) : -1;
      const existingHeroId = existing ? Number(existing.hero.id || 0) : -1;
      const heroId = Number(hero.id || 0);
      const rarityRank = getWalletHeroRarityRank(hero);
      const existingRarityRank = existing ? getWalletHeroRarityRank(existing.hero) : -1;
      if (!existing || rarityRank > existingRarityRank || (rarityRank === existingRarityRank && level > existingLevel) || (rarityRank === existingRarityRank && level === existingLevel && heroId > existingHeroId)) {
        bestByChampionKey.set(key, { key, hero, definition: CHAMPION_DEFINITIONS[key] });
      }
    }
    const roster = Array.from(bestByChampionKey.values());
    if (!roster.length) roster.push(...getChampionTestRoster());
    return roster.sort((a, b) => {
      const rarityDiff = getWalletHeroRarityRank(b.hero) - getWalletHeroRarityRank(a.hero);
      if (rarityDiff !== 0) return rarityDiff;
      const levelDiff = Number(b.hero.level || 0) - Number(a.hero.level || 0);
      if (levelDiff !== 0) return levelDiff;
      return String(a.definition.label || '').localeCompare(String(b.definition.label || ''));
    });
  }

  function updateChampionDetectionFromRoster() {
    const previousSnapshot = game.selectedChampionSnapshot ? {
      key: game.selectedChampionSnapshot.key,
      hero: { ...(game.selectedChampionSnapshot.hero || {}) },
      definition: game.selectedChampionSnapshot.definition,
    } : null;
    const lockChampionForActiveRun = !!(game.selectedChampionConfirmed && previousSnapshot && hasStartedRunForChampionLock());
    game.championRoster = getDetectedChampionRoster();
    const selected = getSelectedChampionRecord();
    if (lockChampionForActiveRun) {
      game.selectedChampionKey = previousSnapshot.key || game.selectedChampionKey;
      game.selectedChampionHeroId = String(previousSnapshot.hero?.id || game.selectedChampionHeroId || '');
      game.selectedChampionSnapshot = previousSnapshot;
    } else if (selected && game.selectedChampionConfirmed) {
      game.selectedChampionSnapshot = { key: selected.key, hero: { ...selected.hero }, definition: selected.definition };
    }
    if (!selected && game.championRoster.length) {
      if (game.selectedChampionConfirmed && game.selectedChampionKey) {
        const lockedMatch = game.championRoster.find((entry) => entry && entry.key === game.selectedChampionKey);
        if (lockedMatch) {
          game.selectedChampionKey = lockedMatch.key;
          game.selectedChampionHeroId = String(lockedMatch.hero.id);
          game.selectedChampionSnapshot = { key: lockedMatch.key, hero: { ...lockedMatch.hero }, definition: lockedMatch.definition };
        }
      } else {
        game.selectedChampionKey = '';
        game.selectedChampionHeroId = '';
        game.selectedChampionSnapshot = null;
        if (!game.selectedChampionConfirmed && Number(game.waveNumber || 0) === 0 && !game.runningWave) {
          game.championModalForceChoice = false;
        }
      }
    }
    if (!game.championRoster.length && !game.selectedChampionConfirmed) {
      game.selectedChampionKey = '';
      game.selectedChampionHeroId = '';
      game.selectedChampionConfirmed = false;
      game.selectedChampionSnapshot = null;
      game.championModalForceChoice = false;
    }
    renderChampionPanel();
  }

  function ensureChampionSelectionReady(options = {}) {
    const roster = Array.isArray(game.championRoster) ? game.championRoster : [];
    if (!roster.length) return null;
    let selected = getSelectedChampionRecord();
    if (!selected) {
      return null;
    }
    if (selected && options.autoConfirm && !game.selectedChampionConfirmed) {
      game.selectedChampionConfirmed = true;
      game.selectedChampionSnapshot = { key: selected.key, hero: { ...selected.hero }, definition: selected.definition };
      game.championModalForceChoice = false;
    }
    return selected;
  }

  function renderChampionCards(container, options = {}) {
    if (!container) return;
    const selected = getSelectedChampionRecord();
    const roster = Array.isArray(game.championRoster) ? game.championRoster : [];
    const visibleRoster = options.selectedOnly && selected ? [selected] : roster;
    container.innerHTML = '';
    const expandedHeroId = String(game.championSideExpandedHeroId || '');
    for (const entry of visibleRoster) {
      const hero = entry.hero;
      const definition = entry.definition;
      const heroId = String(hero.id);
      const isSelected = selected && selected.key === entry.key && String(selected.hero.id) === heroId;
      if (options.sideMenu) {
        const isExpanded = expandedHeroId === heroId;
        const card = document.createElement('div');
        card.className = `champion-card champion-card-side${isSelected ? ' selected' : ''}${isExpanded ? ' expanded' : ''}`;
        const waited = getChampionWavesWaited();
        const deployed = !!(game.championDeployedTowerId && game.towers.some((tower) => tower.id === game.championDeployedTowerId));
        const required = getChampionRequiredWaitWaves();
        const placement = getChampionDeployPreview(waited);
        const remaining = Math.max(0, required - waited);
        const activeLine = deployed
          ? `Active through wave ${escapeHtml(String(game.championActiveUntilWave || ''))}`
          : (placement.ready ? `Ready now • lasts ${escapeHtml(String(placement.duration || 12))} waves` : `${escapeHtml(String(remaining))} wave${remaining === 1 ? '' : 's'} until deploy`);
        const chainName = escapeHtml(hero.chainName || hero.chain || 'NFT');
        const detailsShouldShow = isSelected || isExpanded || !!game.selectedChampionConfirmed;
        const detailsHtml = detailsShouldShow ? `
          <div class="champion-card-side-details">
            <div class="champion-detail-row"><span>Hero</span><strong>#${escapeHtml(String(hero.id || ''))}</strong></div>
            <div class="champion-detail-row"><span>Chain</span><strong>${chainName}</strong></div>
            <div class="champion-detail-row"><span>Status</span><strong>${activeLine}</strong></div>
            <p class="champion-side-summary">${escapeHtml(definition.summary || '')}</p>
            <ul class="champion-side-skills">${(definition.skills || []).map((skill) => `<li>${formatChampionSkillMarkup(skill)}</li>`).join('')}</ul>
          </div>` : '';
        card.innerHTML = `<button type="button" class="champion-card-side-toggle champion-card-side-compact" aria-expanded="${detailsShouldShow ? 'true' : 'false'}"><div class="champion-card-header champion-card-header-compact"><img class="champion-card-portrait champion-card-portrait-compact" src="${getChampionPortraitImage(hero, definition.key)}" alt="${definition.label}"><div class="champion-card-headtext champion-card-headtext-compact"><h3>${definition.label}</h3><div class="champion-card-meta champion-card-meta-compact"><span class="champion-chip">Lvl ${hero.level}</span><span class="champion-chip">Hero #${escapeHtml(String(hero.id || ''))}</span></div>${getChampionRarityRowMarkup(hero)}</div></div></button>${detailsHtml}`;
        const toggle = card.querySelector('.champion-card-side-toggle');
        if (toggle) {
          toggle.addEventListener('click', () => {
            if (game.selectedChampionConfirmed) {
              const locked = getSelectedChampionRecord();
              showBanner(locked ? `${locked.definition.label} is locked in for this run.` : 'Champion is locked in for this run.', 1800);
              return;
            }
            game.selectedChampionKey = entry.key;
            game.selectedChampionHeroId = heroId;
            if (!game.selectedChampionConfirmed) game.selectedChampionSnapshot = { key: entry.key, hero: { ...hero }, definition };
            game.championSideExpandedHeroId = isExpanded ? '' : heroId;
            renderChampionPanel();
            if (options.walletFolder) renderWalletHeroBonusPanel();
          });
        }
        container.appendChild(card);
        continue;
      }
      const card = document.createElement(options.informational ? 'div' : 'button');
      if (!options.informational) card.type = 'button';
      card.className = `champion-card${isSelected ? ' selected' : ''}${options.informational ? ' champion-info-card' : ''}`;
      const canSelectFromInfo = options.informational && !game.selectedChampionConfirmed && canChooseChampionNow();
      card.innerHTML = `<div class="champion-card-header"><img class="champion-card-portrait" src="${getChampionPortraitImage(hero, definition.key)}" alt="${definition.label}"><div class="champion-card-headtext"><h3>${definition.label}</h3><div class="champion-card-meta"><span class="champion-chip">${hero.chainName}</span><span class="champion-chip">Lvl ${hero.level}</span><span class="champion-chip">Hero ${hero.id}</span></div>${getChampionRarityRowMarkup(hero)}</div></div><p>${definition.summary}</p><ul>${definition.skills.map((skill) => `<li>${formatChampionSkillMarkup(skill)}</li>`).join('')}</ul>${canSelectFromInfo ? `<button type="button" class="wallet-btn champion-info-select-btn" data-champion-info-select="${escapeHtml(heroId)}">${isSelected ? 'Selected - Lock In' : `Select ${escapeHtml(definition.label)}`}</button>` : ''}`;
      const selectEntry = (event = null) => {
        if (event) {
          event.preventDefault();
          event.stopPropagation();
        }
        if (game.selectedChampionConfirmed) {
          const locked = getSelectedChampionRecord();
          showBanner(locked ? `${locked.definition.label} is locked in for this run.` : 'Champion is locked in for this run.', 1800);
          return;
        }
        if (!canChooseChampionNow()) {
          showBanner('Champion selection must happen before the first wave starts.', 2000);
          return;
        }
        game.selectedChampionKey = entry.key;
        game.selectedChampionHeroId = heroId;
        game.selectedChampionSnapshot = { key: entry.key, hero: { ...hero }, definition };
        renderChampionPanel();
        if (options.informational && els.championInfoModalBody) renderChampionCards(els.championInfoModalBody, { informational: true });
        if (options.informational) showChampionLockModal();
      };
      if (options.informational) {
        const selectBtn = card.querySelector('[data-champion-info-select]');
        if (selectBtn) selectBtn.addEventListener('click', selectEntry);
        card.addEventListener('click', selectEntry);
      } else {
        card.addEventListener('click', (event) => {
          event.preventDefault();
          event.stopPropagation();
          if (game.selectedChampionConfirmed) {
            const locked = getSelectedChampionRecord();
            showBanner(locked ? `${locked.definition.label} is locked in for this run.` : 'Champion is locked in for this run.', 1800);
            return;
          }
          game.selectedChampionKey = entry.key;
          game.selectedChampionHeroId = heroId;
          if (!game.selectedChampionConfirmed) game.selectedChampionSnapshot = { key: entry.key, hero: { ...hero }, definition };
          renderChampionPanel();
          if (options.inModal && els.championModalBody) {
            renderChampionCards(els.championModalBody, { inModal: true });
          }
        });
      }
      container.appendChild(card);
    }
  }

  function canChooseChampionNow() {
    return !game.runningWave && (Number(game.waveNumber || 0) === 0 || isAwaitingManualStartAfterWaveJump());
  }

  function hasStartedRunForChampionLock() {
    return Number(game.waveNumber || 0) > 0 || !!game.runningWave || Number(game.activeWaveBase || 0) > 0 || game.phase === SETUP_PHASES.GAME_OVER;
  }

  function shouldLockWalletHeroRefreshDuringRun() {
    return (hasStartedRunForChampionLock() && !isStartingWalletHeroPlacementWindow()) || !!game.continueOfferPending || !!game.continueSnapshot;
  }

  function syncWalletHeroRefreshButtonState() {
    if (!els.refreshWalletHeroesBtn) return;
    const locked = shouldLockWalletHeroRefreshDuringRun();
    els.refreshWalletHeroesBtn.disabled = locked || !!game.walletHeroLoadPending;
    els.refreshWalletHeroesBtn.title = locked
      ? 'NFT refresh is disabled while a run is active so champion timing cannot reset.'
      : 'Refresh wallet NFTs.';
    els.refreshWalletHeroesBtn.textContent = game.walletHeroLoadPending ? 'Refreshing NFTs…' : 'Refresh NFTs';
  }

  function showWalletHeroRefreshLockedMessage() {
    showBanner('NFT refresh is disabled while a game is running so champion wave count stays locked.', 2400);
  }

  function showChampionTimingDebug(reason = '') {
    try {
      console.debug('[champion-timing]', {
        reason,
        waveNumber: Number(game.waveNumber || 0),
        activeWaveBase: Number(game.activeWaveBase || 0),
        waitAnchor: Number(game.championWaitAnchorWave || 0),
        waited: getChampionWavesWaited(),
        selected: String(game.selectedChampionKey || ''),
        selectedHeroId: String(game.selectedChampionHeroId || ''),
        confirmed: !!game.selectedChampionConfirmed,
        deployedTowerId: game.championDeployedTowerId || null,
        activeUntil: Number(game.championActiveUntilWave || 0),
      });
    } catch (_error) {}
  }

  function showChampionInfoModal() {
    if (!els.championInfoModal || !els.championInfoModalBody || !(game.championRoster || []).length) {
      showBanner('No champion NFTs detected yet.', 1800);
      return false;
    }
    try {
      hideRewardPayoutNoticeModal();
      closeIntroModal();
      closeBountyModal();
      closeQuestsModal();
      closeTrackedRunsModal();
      closeKnownRelicsModal();
      closeContinueOfferModal();
      closeGuestConnectConfirmModal({ preserveIntroState: true });
      closeSeerIntroModal({ keepBoardLocked: true, preserveIntroState: true });
      closeStartModeModal({ keepBoardLocked: true, preserveIntroState: true });
    } catch (_error) {}
    renderChampionCards(els.championInfoModalBody, { informational: true });
    document.body.classList.add('intro-open');
    game.introOpen = true;
    syncStatusOverlayVisibility(true);
    els.championInfoModal.style.zIndex = '21050';
    els.championInfoModal.style.pointerEvents = 'auto';
    const card = els.championInfoModal.querySelector('.intro-modal-card');
    if (card) card.style.pointerEvents = 'auto';
    els.championInfoModal.classList.remove('hidden');
    els.championInfoModal.setAttribute('aria-hidden', 'false');
    return true;
  }

  function hideChampionInfoModal() {
    if (!els.championInfoModal) return;
    els.championInfoModal.classList.add('hidden');
    els.championInfoModal.setAttribute('aria-hidden', 'true');
    syncIntroOpenClassFromVisibleModals();
  }

  function showChampionModal(forceOpen = false) {
    if (!els.championModal || !(game.championRoster || []).length) return false;
    if (game.selectedChampionConfirmed) {
      const selected = getSelectedChampionRecord();
      showBanner(selected ? `${selected.definition.label} is locked in for this run.` : 'Champion is locked in for this run.', 1800);
      return false;
    }
    if (!canChooseChampionNow()) {
      showBanner('Choose your champion before the first wave starts.', 2000);
      return false;
    }
    if (game.runningWave || !(Number(game.waveNumber || 0) === 0 || isAwaitingManualStartAfterWaveJump())) {
      return false;
    }
    ensureChampionSelectionReady({ autoConfirm: false });
    try {
      hideRewardPayoutNoticeModal();
      closeIntroModal();
      closeBountyModal();
      closeQuestsModal();
      closeTrackedRunsModal();
      closeKnownRelicsModal();
      closeContinueOfferModal();
      closeGuestConnectConfirmModal({ preserveIntroState: true });
      closeSeerIntroModal({ keepBoardLocked: true, preserveIntroState: true });
      closeStartModeModal({ keepBoardLocked: true, preserveIntroState: true });
    } catch (_error) {}
    renderChampionCards(els.championModalBody, { inModal: true });
    document.body.classList.add('intro-open');
    game.introOpen = true;
    syncStatusOverlayVisibility(true);
    els.championModal.style.zIndex = '21050';
    els.championModal.style.pointerEvents = 'auto';
    const championCard = els.championModal.querySelector('.intro-modal-card');
    if (championCard) championCard.style.pointerEvents = 'auto';
    els.championModal.classList.remove('hidden');
    els.championModal.setAttribute('aria-hidden', 'false');
    if (!forceOpen && !game.championModalForceChoice && game.selectedChampionConfirmed) return false;
    return true;
  }

  function hideChampionModal() {
    if (!els.championModal) return;
    els.championModal.classList.add('hidden');
    els.championModal.setAttribute('aria-hidden', 'true');
    syncIntroOpenClassFromVisibleModals();
  }

  function cancelChampionModal() {
    hideChampionModal();
    if (requireChampionSelectionBeforeStart()) {
      showBanner('Choose a champion before starting the run.', 1800);
    }
  }

  function showChampionLockModal() {
    const selected = getSelectedChampionRecord();
    if (!selected || !els.championLockModal || !els.championLockText) return false;
    els.championLockText.textContent = `Are you sure? ${selected.definition.label} will be your champion for this entire run.`;
    document.body.classList.add('intro-open');
    game.introOpen = true;
    syncStatusOverlayVisibility(true);
    els.championLockModal.style.zIndex = '21060';
    els.championLockModal.style.pointerEvents = 'auto';
    const lockCard = els.championLockModal.querySelector('.intro-modal-card');
    if (lockCard) lockCard.style.pointerEvents = 'auto';
    els.championLockModal.classList.remove('hidden');
    els.championLockModal.setAttribute('aria-hidden', 'false');
    game.championLockPending = true;
    return true;
  }

  function hideChampionLockModal() {
    if (!els.championLockModal) return;
    els.championLockModal.classList.add('hidden');
    els.championLockModal.setAttribute('aria-hidden', 'true');
    game.championLockPending = false;
    syncIntroOpenClassFromVisibleModals();
  }

  function finalizeChampionConfirmation() {
    const selected = getSelectedChampionRecord();
    if (!selected) {
      hideChampionLockModal();
      showBanner('Pick a champion first.', 1600);
      return false;
    }
    game.selectedChampionConfirmed = true;
    game.selectedChampionSnapshot = { key: selected.key, hero: { ...selected.hero }, definition: selected.definition };
    game.championModalForceChoice = false;
    hideChampionLockModal();
    hideChampionModal();
    hideChampionInfoModal();
    setChampionPanelCollapsed(false);
    renderChampionPanel();
    showBanner(`${selected.definition.label} locked in for this run.`, 1800);
    return true;
  }


  function confirmSelectedChampion() {
    const selected = getSelectedChampionRecord();
    if (!selected) {
      showBanner('Pick a champion first.', 1600);
      return false;
    }
    if (!canChooseChampionNow()) {
      showBanner('Champion selection must happen before the first wave starts.', 2000);
      hideChampionModal();
      return false;
    }
    if (game.selectedChampionConfirmed) {
      showBanner(`${selected.definition.label} is already locked in for this run.`, 1800);
      return true;
    }
    return finalizeChampionConfirmation();
  }

  function renderChampionPanel() {
    game.lastChampionPanelWaveRendered = Number(game.waveNumber || 0);
    if (!els.championPanel || !els.championStatus || !els.championBody) return;
    const hasWallet = !!getConnectedWalletAddress();
    const selectedForPanel = getSelectedChampionRecord();
    const showSelectedChampionPanel = !!(hasWallet && selectedForPanel && game.selectedChampionConfirmed);
    els.championPanel.classList.toggle('hidden', !showSelectedChampionPanel);
    els.championPanel.setAttribute('aria-hidden', showSelectedChampionPanel ? 'false' : 'true');
    if (els.championInfoMenuBtn) {
      const showChampionInfoMenu = false;
      els.championInfoMenuBtn.classList.toggle('hidden', !showChampionInfoMenu);
      els.championInfoMenuBtn.disabled = !showChampionInfoMenu;
    }
    if (!showSelectedChampionPanel) {
      els.championStatus.textContent = 'Connect a wallet to detect champion NFTs on DFK Chain and Metis.';
      els.championBody.innerHTML = '';
      renderChampionCollapsedPreview();
      setChampionPanelCollapsed(!!game.championPanelCollapsed);
      return;
    }
    if (game.walletHeroLoadPending) {
      els.championStatus.textContent = 'Checking DFK Chain and Metis for champion NFTs…';
    } else if (!(game.championRoster || []).length) {
      els.championStatus.textContent = 'No champion NFTs detected on DFK Chain or Metis for this wallet.';
    } else {
      const selected = getSelectedChampionRecord();
      const waited = getChampionWavesWaited();
      const deployed = !!(game.championDeployedTowerId && game.towers.some((tower) => tower.id === game.championDeployedTowerId));
      const required = getChampionRequiredWaitWaves();
      const ready = !deployed && waited >= required;
      const duration = waited >= 40 ? 24 : 12;
      const rosterLabel = canUseChampionWaveOneOverride() && !(game.allWalletHeroRoster || []).length
        ? `${(game.championRoster || []).length} test champion${game.championRoster.length === 1 ? '' : 's'} available.`
        : `${(game.championRoster || []).length} champion NFT${game.championRoster.length === 1 ? '' : 's'} detected.`;
      els.championStatus.innerHTML = `${rosterLabel} ${deployed ? `Champion deployed through wave ${game.championActiveUntilWave}.` : `Waited ${waited} wave${waited === 1 ? '' : 's'}${ready ? ` • deploy now for ${duration} waves` : ` • deploy unlocks at ${required} waited wave${required === 1 ? '' : 's'}`}.`}`;
    }
    if (selectedForPanel) {
      renderChampionCards(els.championBody, { sideMenu: true, selectedOnly: true });
    } else {
      els.championBody.innerHTML = (game.championRoster || []).length
        ? '<div class="champion-panel-empty">Finish the board setup, then choose one champion for this run.</div>'
        : '';
    }
    renderChampionCollapsedPreview();
    if (els.chooseChampionBtn) {
      els.chooseChampionBtn.disabled = true;
      els.chooseChampionBtn.textContent = '';
      els.chooseChampionBtn.classList.add('hidden');
    }
    if (els.deployChampionBtn) {
      const selected = getSelectedChampionRecord();
      const hasChampionRoster = !!((game.championRoster || []).length);
      const waited = getChampionWavesWaited();
      const deployed = !!(game.championDeployedTowerId && game.towers.some((tower) => tower.id === game.championDeployedTowerId));
      const required = getChampionRequiredWaitWaves();
      const ready = waited >= required && !deployed;
      const showInfoButton = hasChampionRoster && !game.selectedChampionConfirmed && !deployed;
      els.deployChampionBtn.disabled = showInfoButton ? true : (!selected || deployed || !!game.placingHeroType);
      els.deployChampionBtn.textContent = 'Deploy';
      els.deployChampionBtn.title = showInfoButton ? 'Champion selection opens after board setup.' : (ready ? 'Deploy the selected champion now.' : `Champion is resting. ${Math.max(0, required - waited)} wave${Math.max(0, required - waited) === 1 ? '' : 's'} until normal deploy.`);
      els.deployChampionBtn.classList.toggle('hidden', showInfoButton || (!!game.championPanelCollapsed && ready));
    }
    setChampionPanelCollapsed(!!game.championPanelCollapsed);
  }

  function requireChampionSelectionBeforeStart() {
    return !!((game.championRoster || []).length && !game.selectedChampionConfirmed && (Number(game.waveNumber || 0) === 0 || isAwaitingManualStartAfterWaveJump()));
  }

  async function payForChampionEarlyDeploy(selected) {
    const paymentAsset = getPreferredDfkTokenPaymentAsset();
    const priceWei = getDfkPaymentWeiForJewelAmount(CHAMPION_EARLY_DEPLOY_JEWEL_COST, paymentAsset);
    const priceLabel = getDfkPaymentLabelForJewelAmount(CHAMPION_EARLY_DEPLOY_JEWEL_COST, paymentAsset);
    return await performDfkJewelTrade('jewel_champion_early_deploy', priceWei, `${priceLabel} early champion deployment`, {
      championKey: selected?.key || '',
      championHeroId: String(selected?.hero?.id || ''),
      championLabel: selected?.definition?.label || 'Champion',
      paymentAsset,
      treasuryAddress: paymentAsset === 'native_ron' ? DFK_RON_TREASURY_ADDRESS : DFK_JEWEL_TREASURY_ADDRESS,
    });
  }

  function closeChampionEarlyDeployModal() {
    const modal = document.getElementById('championEarlyDeployModal');
    if (modal) modal.remove();
    syncIntroOpenClassFromVisibleModals();
  }

  function showChampionEarlyDeployUsedModal(remaining) {
    closeChampionEarlyDeployModal();
    openAnnouncementModal({
      kicker: 'Champion Resting',
      title: 'Early Deploy Used',
      bodyHtml: `<p>Early champion deployment has already been used this run. Wait ${Math.max(1, Number(remaining || 1))} more wave${Number(remaining || 1) === 1 ? '' : 's'} to deploy.</p>`,
      okText: 'Close',
    });
    els.guideIntroToggleBtn?.classList.add('hidden');
    els.guideLoreToggleBtn?.classList.add('hidden');
  }

  function showChampionEarlyDeployModal(selected, remaining) {
    if (!selected) return false;
    closeChampionEarlyDeployModal();
    const modal = document.createElement('div');
    modal.id = 'championEarlyDeployModal';
    modal.className = 'intro-modal champion-early-deploy-modal';
    modal.setAttribute('aria-hidden', 'false');
    modal.innerHTML = `
      <div class="intro-modal-card panel" role="dialog" aria-modal="true" aria-labelledby="championEarlyDeployTitle">
        <div class="intro-modal-header">
          <div>
            <div class="intro-kicker">Champion Resting</div>
            <h2 id="championEarlyDeployTitle">${escapeHtml(selected.definition.label)} is resting</h2>
          </div>
        </div>
        <div class="intro-body">
          <p>${escapeHtml(selected.definition.label)} is resting for ${Math.max(1, Number(remaining || 1))} more wave${Number(remaining || 1) === 1 ? '' : 's'}. Deploy them immediately for ${escapeHtml(getDfkPaymentLabelForJewelAmount(CHAMPION_EARLY_DEPLOY_JEWEL_COST, getPreferredDfkTokenPaymentAsset()))}?</p>
          <p id="championEarlyDeployStatus" class="muted">This can only be used once per run.</p>
        </div>
        <div class="intro-modal-footer">
          <button id="championEarlyDeployConfirmBtn" type="button">Deploy</button>
          <button id="championEarlyDeployCancelBtn" class="secondary" type="button">Cancel</button>
        </div>
      </div>`;
    document.body.appendChild(modal);
    document.body.classList.add('intro-open');
    game.introOpen = true;
    syncStatusOverlayVisibility(true);
    const confirmBtn = modal.querySelector('#championEarlyDeployConfirmBtn');
    const cancelBtn = modal.querySelector('#championEarlyDeployCancelBtn');
    const statusEl = modal.querySelector('#championEarlyDeployStatus');
    const cancel = () => closeChampionEarlyDeployModal();
    cancelBtn?.addEventListener('click', cancel);
    modal.addEventListener('click', (event) => {
      if (event.target === modal) cancel();
    });
    confirmBtn?.addEventListener('click', async () => {
      if (game.championEarlyDeployUsed) {
        closeChampionEarlyDeployModal();
        showChampionEarlyDeployUsedModal(Math.max(0, getChampionRequiredWaitWaves() - getChampionWavesWaited()));
        return;
      }
      confirmBtn.disabled = true;
      if (cancelBtn) cancelBtn.disabled = true;
      confirmBtn.textContent = 'Submitting';
      if (cancelBtn) cancelBtn.textContent = 'Submitting';
      if (statusEl) statusEl.textContent = 'Opening wallet transaction...';
      try {
        await payForChampionEarlyDeploy(selected);
        game.championEarlyDeployUsed = true;
        game.championEarlyDeployPending = true;
        if (statusEl) statusEl.textContent = 'Payment confirmed. Deploy button unlocked in the hire menu.';
        closeChampionEarlyDeployModal();
        showBanner(`Deploy ${selected.definition.label} unlocked in the hire menu.`, 2600);
        renderHirePanel();
        renderChampionPanel();
        render();
      } catch (error) {
        if (statusEl) statusEl.textContent = error && error.message ? error.message : 'Early deployment payment failed.';
        confirmBtn.disabled = false;
        if (cancelBtn) cancelBtn.disabled = false;
        confirmBtn.textContent = 'Deploy';
        if (cancelBtn) cancelBtn.textContent = 'Cancel';
      }
    });
    return true;
  }

  function beginChampionPlacement(options = {}) {
    const inRun = Number(game.waveNumber || 0) > 0 || game.runningWave;
    const selected = ensureChampionSelectionReady({ autoConfirm: inRun });
    const waited = getChampionWavesWaited();
    if (game.placingHeroType && String(game.placingHeroType).startsWith('champion_')) {
      if (selected && game.placingHeroType === selected.definition.towerType) {
        showBanner(`${selected.definition.label} placement is already active. Tap an open tile to deploy.`, 2200);
        renderChampionPanel();
        render();
        return;
      }
      game.placingHeroType = null;
      game.placingHeroCost = 0;
      game.placingHeroUsesBonus = false;
      game.placingSatelliteSourceId = null;
      game.placingWalletHeroId = null;
      game.championPlacementPending = null;
    }
    if (!selected || !game.selectedChampionConfirmed) {
      if ((game.championRoster || []).length) {
        showChampionInfoModal();
      } else {
        showBanner('No champion is available for this run.', 1800);
      }
      return;
    }
    if (game.championDeployedTowerId && game.towers.some((tower) => tower.id === game.championDeployedTowerId)) {
      showBanner('Champion is already on the field.', 1500);
      return;
    }
    const required = getChampionRequiredWaitWaves();
    showChampionTimingDebug('begin-placement');
    const earlyDeployUnlocked = !!game.championEarlyDeployPending;
    if (waited < required && !options.allowEarly && !earlyDeployUnlocked) {
      const remaining = Math.max(0, required - waited);
      if (game.championEarlyDeployUsed) {
        showChampionEarlyDeployUsedModal(remaining);
      } else {
        showChampionEarlyDeployModal(selected, remaining);
      }
      return;
    }
    hideChampionLockModal();
    hideChampionModal();
    game.placingHeroType = selected.definition.towerType;
    game.placingHeroCost = 0;
    game.placingHeroUsesBonus = false;
    game.placingSatelliteSourceId = null;
    game.placingWalletHeroId = null;
    game.championPlacementPending = {
      key: selected.key,
      heroId: String(selected.hero?.id || ''),
      towerType: selected.definition.towerType,
      waitedAtStart: waited,
      earlyDeploy: waited < required && earlyDeployUnlocked,
      startedAt: now(),
    };
    showBanner(`Place ${selected.definition.label} on any open tile. Champions ignore the normal hero cap.`, 2200);
    renderChampionPanel();
    render();
  }

  function retireChampionTower(reason = 'Champion retired to recover.') {
    const tower = game.championDeployedTowerId ? game.towers.find((entry) => entry.id === game.championDeployedTowerId) : null;
    if (tower) {
      const tile = tileAt(tower.x, tower.y);
      if (tile && tile.towerId === tower.id) tile.towerId = null;
      if (game.selectedChampionSnapshot && String(game.selectedChampionSnapshot.hero?.id || '') === String(tower.walletHeroId || '')) game.selectedChampionSnapshot.hero.level = Math.max(Number(game.selectedChampionSnapshot.hero.level || 1), Number(tower.level || 1));
      game.towers = game.towers.filter((entry) => entry.id !== tower.id);
      if (game.selectedId === tower.id) game.selectedId = null;
    }
    if (game.championDeployedTowerId) {
      game.championDeployedTowerId = null;
      game.championActiveUntilWave = 0;
      game.championPlacementPending = null;
      game.championEarlyDeployPending = false;
      game.championLastReminderWaited = 0;
      game.championWaitAnchorWave = Number(game.waveNumber || 0);
      showBanner(reason, 1800);
      renderChampionPanel();
      render();
    }
  }

  function maybeRetireChampionBetweenWaves() {
    if (!game.championDeployedTowerId || !game.championActiveUntilWave) return;
    if (Number(game.waveNumber || 0) >= Number(game.championActiveUntilWave || 0)) {
      retireChampionTower(`Champion energy spent. They retired to recover until you wait another ${getChampionRequiredWaitWaves()} wave${getChampionRequiredWaitWaves() === 1 ? '' : 's'}.`);
    }
  }

