(function wirePlayIntroAgainButton() {
  function hook() {
    const btn = document.getElementById('playIntroAgainBtn');
    if (!btn || btn.dataset.wired === '1') return;
    btn.dataset.wired = '1';
    btn.addEventListener('click', () => {
      try {
        if (typeof playStorySequence === 'function') {
          playStorySequence();
          return;
        }
      } catch (error) {}
      try {
        if (typeof openIntroModal === 'function') {
          openIntroModal();
          return;
        }
      } catch (error) {}
      try {
        if (typeof renderIntroPage === 'function') {
          renderIntroPage();
        }
      } catch (error) {}
    });
  }
  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', hook);
  } else {
    hook();
  }
  setTimeout(hook, 100);
})();







function closeJewelReceivedLightwindow() {
  try {
    const backdrop = document.getElementById('jewelReceivedLightwindowBackdrop');
    if (backdrop) backdrop.remove();
    document.body.classList.remove('intro-open');
  } catch (_) {}
}

function showJewelReceivedLightwindow(amountText) {
  try {
    closeJewelReceivedLightwindow();
    const backdrop = document.createElement('div');
    backdrop.id = 'jewelReceivedLightwindowBackdrop';
    backdrop.className = 'jewel-received-lightwindow-backdrop';
    backdrop.innerHTML = ''
      + '<div class="jewel-received-lightwindow" role="dialog" aria-modal="true">'
      + '  <div class="jewel-received-kicker">TREASURY DELIVERY</div>'
      + '  <div class="jewel-received-title">' + String(amountText || '').trim() + ' Jewel received!</div>'
      + '  <div class="jewel-received-copy">Click anywhere to close.</div>'
      + '  <button type="button" class="jewel-received-close">Hell yeah</button>'
      + '</div>';
    backdrop.addEventListener('click', function() { closeJewelReceivedLightwindow(); });
    const panel = backdrop.querySelector('.jewel-received-lightwindow');
    panel.addEventListener('click', function(ev) { ev.stopPropagation(); });
    const btn = backdrop.querySelector('.jewel-received-close');
    if (btn) btn.addEventListener('click', function(ev) { ev.preventDefault(); ev.stopPropagation(); closeJewelReceivedLightwindow(); });
    document.body.appendChild(backdrop);
    document.body.classList.add('intro-open');
  } catch (_) {}
}


function observeRewardSentForJewelReceived() {
  try {
    const obs = new MutationObserver(() => {
      const modal = document.querySelector('.reward-sent-modal, #rewardSentModal, [data-reward-sent-modal]');
      if (!modal) return;
      if (modal.dataset && modal.dataset.jewelReceivedObserved === '1') return;
      const text = (modal.textContent || '');
      const match = text.match(/([0-9]+(?:\.[0-9]+)?)\s*jewel/i);
      if (match) {
        if (modal.dataset) modal.dataset.jewelReceivedObserved = '1';
        showJewelReceivedLightwindow(match[1]);
      }
    });
    obs.observe(document.documentElement || document.body, { childList: true, subtree: true });
  } catch (_) {}
}
observeRewardSentForJewelReceived();


function getTopMenuDailyQuestBoardSnapshot() {
  try {
    if (game && game.dailyQuestBoard && typeof game.dailyQuestBoard === 'object') {
      const board = game.dailyQuestBoard;
      if (Array.isArray(board.questIds) && board.questIds.length) return board;
    }
  } catch (_error) {}
  try {
    const playerKey = (typeof getDailyQuestPlayerKey === 'function') ? getDailyQuestPlayerKey() : ((typeof getConnectedWalletAddress === 'function' && getConnectedWalletAddress()) || 'guest');
    const dateKey = (typeof getDailyQuestDateKey === 'function') ? getDailyQuestDateKey() : new Date().toISOString().slice(0, 10);
    let cycle = 0;
    try {
      if (typeof getDailyQuestTestCycle === 'function') cycle = Math.max(0, Number(getDailyQuestTestCycle(playerKey, dateKey) || 0));
    } catch (_error) {}
    const cycleSuffix = cycle > 0 ? `:cycle:${cycle}` : '';
    const storageKey = (typeof getDailyQuestStorageKey === 'function')
      ? getDailyQuestStorageKey(playerKey, dateKey)
      : `dfkDefenderDailyQuests:v5:${playerKey}:${dateKey}${cycleSuffix}`;
    const stored = JSON.parse(localStorage.getItem(storageKey) || 'null');
    return stored && typeof stored === 'object' ? stored : null;
  } catch (_error) {
    return null;
  }
}

function getDailyQuestClaimedTotalStorageKey(playerKey, dateKey) {
  return `dfkDefenderDailyClaimedTotal:v1:${String(playerKey || 'guest').toLowerCase()}:${String(dateKey || '').trim()}`;
}

function readStoredDailyQuestClaimedJewelTotal(playerKey, dateKey) {
  try {
    const key = getDailyQuestClaimedTotalStorageKey(playerKey, dateKey);
    const raw = localStorage.getItem(key);
    const value = Number(raw || 0);
    return Number.isFinite(value) && value >= 0 ? value : 0;
  } catch (_error) {
    return 0;
  }
}

function writeStoredDailyQuestClaimedJewelTotal(total, playerKey, dateKey) {
  try {
    const safeTotal = Math.max(0, Number(total || 0));
    const key = getDailyQuestClaimedTotalStorageKey(playerKey, dateKey);
    localStorage.setItem(key, String(safeTotal));
    return safeTotal;
  } catch (_error) {
    return Math.max(0, Number(total || 0));
  }
}

function addStoredDailyQuestClaimedJewelTotal(amount, playerKey, dateKey) {
  try {
    const current = readStoredDailyQuestClaimedJewelTotal(playerKey, dateKey);
    return writeStoredDailyQuestClaimedJewelTotal(current + Math.max(0, Number(amount || 0)), playerKey, dateKey);
  } catch (_error) {
    return 0;
  }
}

function getTopMenuClaimedDailyQuestJewelTotal() {
  let bestTotal = 0;
  try {
    if (typeof getClaimedDailyQuestJewelTotal === 'function') {
      const directTotal = Number(getClaimedDailyQuestJewelTotal() || 0);
      if (Number.isFinite(directTotal) && directTotal >= 0) bestTotal = Math.max(bestTotal, directTotal);
    }
  } catch (_error) {}
  try {
    const board = getTopMenuDailyQuestBoardSnapshot();
    const claimed = board && typeof board.claimed === 'object' && board.claimed ? board.claimed : {};
    const questIds = Array.isArray(board && board.questIds) ? board.questIds : [];
    let total = 0;
    for (const questId of questIds) {
      if (!claimed || !claimed[questId]) continue;
      let quest = null;
      try {
        if (typeof getQuestDefinitionById === 'function') quest = getQuestDefinitionById(questId);
      } catch (_error) {}
      total += Math.max(0, Number(quest && quest.rewardJewel || 0));
    }
    if (Number.isFinite(total) && total >= 0) bestTotal = Math.max(bestTotal, total);
  } catch (_error) {}
  try {
    const board = getTopMenuDailyQuestBoardSnapshot();
    const playerKey = String((board && board.playerKey) || ((typeof getDailyQuestPlayerKey === 'function' && getDailyQuestPlayerKey()) || 'guest')).toLowerCase();
    const dateKey = String((board && board.dateKey) || ((typeof getDailyQuestDateKey === 'function' && getDailyQuestDateKey()) || new Date().toISOString().slice(0, 10))).trim();
    const storedTotal = Number(readStoredDailyQuestClaimedJewelTotal(playerKey, dateKey) || 0);
    if (Number.isFinite(storedTotal) && storedTotal >= 0) bestTotal = Math.max(bestTotal, storedTotal);
  } catch (_error) {}
  return Math.max(0, bestTotal);
}

function getTopMenuDailyQuestResetText() {
  try {
    const now = new Date();
    const nextUtc = new Date(Date.UTC(
      now.getUTCFullYear(),
      now.getUTCMonth(),
      now.getUTCDate() + 1,
      0, 0, 0, 0
    ));
    const totalSeconds = Math.max(0, Math.floor((nextUtc.getTime() - now.getTime()) / 1000));
    if (typeof formatDailyQuestResetCountdown === 'function') {
      return formatDailyQuestResetCountdown(totalSeconds);
    }
    const hours = Math.floor(totalSeconds / 3600);
    const minutes = Math.floor((totalSeconds % 3600) / 60);
    return `${hours}h ${String(minutes).padStart(2, '0')}m`;
  } catch (_error) {
    return '--';
  }
}

function syncTopMenuWalletResources() {
  const trackingSource = document.getElementById('walletTrackingSummary');
  const trackingTarget = document.getElementById('walletTopTrackingSummary');
  const resetTarget = document.getElementById('walletTopResetTimer');

  let nextTrackingText = 'Tracked Runs: -- · Best Wave: --';
  try {
    nextTrackingText = trackingSource
      ? String(trackingSource.textContent || 'Tracked Runs: -- · Best Wave: --').trim()
      : 'Tracked Runs: -- · Best Wave: --';
  } catch (_error) {}

  let nextResetText = 'Reset timer: --';
  try {
    nextResetText = `Reset timer: ${getTopMenuDailyQuestResetText()}`;
  } catch (_error) {}

  try {
    if (trackingTarget && trackingTarget.textContent !== nextTrackingText) trackingTarget.textContent = nextTrackingText;
    if (resetTarget && resetTarget.textContent !== nextResetText) resetTarget.textContent = nextResetText;
  } catch (_error) {}
}

let topMenuWalletResourceSyncInterval = null;
function installTopMenuWalletResourceSync() {
  try { syncTopMenuWalletResources(); } catch (_error) {}
  try {
    if (topMenuWalletResourceSyncInterval) window.clearInterval(topMenuWalletResourceSyncInterval);
    topMenuWalletResourceSyncInterval = window.setInterval(() => {
      try { syncTopMenuWalletResources(); } catch (_error) {}
    }, 1000);
  } catch (_error) {}
  try {
    document.addEventListener('visibilitychange', () => {
      if (!document.hidden) {
        try { syncTopMenuWalletResources(); } catch (_error) {}
      }
    });
  } catch (_error) {}
}


function refreshTopMenuData(options = {}) {
  const tasks = [];
  // Keep the manual Refresh NFTs button available after a run, but do not
  // automatically re-read NFT rosters from generic top-menu refreshes. The
  // champion wait timer is locked to the selected run snapshot; automatic
  // roster refreshes after game-over are unnecessary and can make the UI look
  // like champion timing was reset.
  const allowHeroRosterAutoRefresh = options.allowHeroRosterAutoRefresh === true;
  try {
    if (typeof refreshWalletJewelTokenBalance === 'function') {
      tasks.push(Promise.resolve(refreshWalletJewelTokenBalance({ skipMilestoneRender: true })).catch(() => null));
    } else if (typeof refreshWalletEconomyDetails === 'function') {
      tasks.push(Promise.resolve(refreshWalletEconomyDetails()).catch(() => null));
    }
  } catch (_error) {}
  try {
    if (options.includeHeroRoster && allowHeroRosterAutoRefresh && typeof loadWalletHeroes === 'function') tasks.push(Promise.resolve(loadWalletHeroes(true)).catch(() => null));
  } catch (_error) {}
  try {
    if (!options.skipRails && window.DFKCryptoRails) {
      if (typeof window.DFKCryptoRails.refreshTreasurySummary === 'function') tasks.push(Promise.resolve(window.DFKCryptoRails.refreshTreasurySummary()).catch(() => null));
      if (typeof window.DFKCryptoRails.refreshRewardClaimsAdmin === 'function') tasks.push(Promise.resolve(window.DFKCryptoRails.refreshRewardClaimsAdmin()).catch(() => null));
      if (options.includeRunBalance && typeof window.DFKCryptoRails.refreshRunBalance === 'function') tasks.push(Promise.resolve(window.DFKCryptoRails.refreshRunBalance()).catch(() => null));
    }
  } catch (_error) {}
  try {
    if (options.includeRunBalance && window.DFKRunTracker && typeof window.DFKRunTracker.refreshSummary === 'function') {
      tasks.push(Promise.resolve(window.DFKRunTracker.refreshSummary({ flushPending: true })).catch(() => null));
    }
  } catch (_error) {}
  return Promise.allSettled(tasks).finally(() => {
    try { syncTopMenuWalletResources(); } catch (_error) {}
    try { updateJewelTradeUi(); } catch (_error) {}
    try { updateRelicSwapUi(); } catch (_error) {}
    try { render(); } catch (_error) {}
    return null;
  });
}

window.refreshTopMenuData = refreshTopMenuData;
document.addEventListener('DOMContentLoaded', () => {
  try { syncTopMenuWalletResources(); } catch (_error) {}
  try { installTopMenuWalletResourceSync(); } catch (_error) {}
  const topRefreshBtn = document.getElementById('walletTopRefreshBtn');
  if (topRefreshBtn && !topRefreshBtn.dataset.boundRefresh) {
    topRefreshBtn.dataset.boundRefresh = '1';
    topRefreshBtn.addEventListener('click', async () => {
      topRefreshBtn.disabled = true;
      try {
        await refreshTopMenuData({ includeRunBalance: true }).catch(() => null);
        try { syncTopMenuWalletResources(); } catch (_error) {}
      } finally {
        window.setTimeout(() => { topRefreshBtn.disabled = false; }, 800);
      }
    });
  }
});




